function operationalModuleFromText(text = "") {
  const lower = String(text || "").toLowerCase();
  if (/\b(doctor|clinic|medicine|pharmacy|patient|health|telehealth|mobile clinic|provider|injury|symptom)\b/.test(lower)) return "Healthcare";
  if (/\b(course|lesson|learn|training|certificate|caption|student|school|study)\b/.test(lower)) return "Learning";
  if (/\b(job|work|role|apply|application|shift|mentor|interview|worker|workforce)\b/.test(lower)) return "Workforce";
  if (/\b(sell|buyer|crop|trade|order|delivery|shipment|route|payment|receipt|market|maize|cassava|farm)\b/.test(lower)) return "AgriTrade";
  if (/\b(drone|field|scan|soil|harvest|pest|crop health|satellite)\b/.test(lower)) return "AgriTech";
  if (/\b(map|location|where|near|route|gps|track)\b/.test(lower)) return "Map & AI";
  return conversationModuleSignal(text).module || "Platform";
}

function operationalWorkflowScores(db) {
  ensureLearningProfile(db.profile);
  ensureWorkforceProfile(db.profile);
  ensureHealthProfile(db.profile);
  ensureTradeProfile(db.profile);
  ensureAiProfile(db.profile);
  ensureCommunicationProfile(db.profile);
  const score = (parts) => {
    const ready = parts.filter(Boolean).length;
    return Math.round((ready / Math.max(1, parts.length)) * 100);
  };
  const scores = [
    {
      module: "Learning",
      percent: score([(db.profile.enrollments || []).length, (db.profile.completedCourses || []).length, (db.profile.certificates || []).length, (db.profile.learningAccommodations || []).length]),
      evidence: `${(db.profile.enrollments || []).length} enrollment(s), ${(db.profile.certificates || []).length} certificate(s)`
    },
    {
      module: "Workforce",
      percent: score([(db.profile.workforceBadges || []).includes("Profile Verified"), (db.profile.applications || []).length, (db.profile.interviews || 0) > 0, (db.profile.shiftSchedule || []).length]),
      evidence: `${(db.profile.applications || []).length} application(s), ${db.profile.interviews || 0} interview(s)`
    },
    {
      module: "Healthcare",
      percent: score([(db.profile.healthIntakes || []).length, (db.profile.carePlans || []).length, (db.profile.representativeConnections || 0) > 0, (db.profile.communicationThreads || []).some(item => item.module === "Healthcare")]),
      evidence: `${(db.profile.healthIntakes || []).length} intake(s), ${(db.profile.carePlans || []).length} care plan(s)`
    },
    {
      module: "AgriTrade",
      percent: score([(db.profile.orders || []).length, (db.profile.tradeMessageThreads || []).length, (db.profile.walletTransactions || []).length, (db.profile.logisticsBookings || []).length]),
      evidence: `${(db.profile.orders || []).length} order(s), ${(db.profile.tradeMessageThreads || []).length} buyer thread(s)`
    },
    {
      module: "AgriTech",
      percent: score([(db.profile.droneMissions || []).length, (db.profile.droneScans || []).length, (db.profile.fieldInterventions || []).length, (db.profile.orders || []).length]),
      evidence: `${(db.profile.droneScans || []).length} scan(s), ${(db.profile.fieldInterventions || []).length} intervention(s)`
    },
    {
      module: "Map & AI",
      percent: score([(db.profile.aiRuns || []).length, (db.profile.mapEvidence || []).length, (db.profile.routeTracking || []).length, (db.profile.integrationEvents || []).some(item => /map|route/i.test(item.action || item.module || ""))]),
      evidence: `${(db.profile.aiRuns || []).length} AI run(s), ${(db.profile.mapEvidence || []).length} map evidence record(s)`
    }
  ];
  return scores;
}

function operationalIntelligenceModel(db, user) {
  const intelligence = ensureOperationalIntelligenceProfile(db.profile);
  const scores = operationalWorkflowScores(db);
  const average = Math.round(scores.reduce((sum, item) => sum + Number(item.percent || 0), 0) / Math.max(1, scores.length));
  const openIssues = (intelligence.issueReports || []).filter(item => !["resolved", "closed"].includes(item.status)).length;
  const activeGoals = (intelligence.goals || []).filter(item => item.status === "active").slice(0, 6);
  const playbookReadiness = Math.min(100, 55 + Math.min(25, (intelligence.playbooks || []).length * 4) + Math.min(20, (intelligence.playbookRuns || []).length * 3));
  return {
    status: average >= 75 ? "operational-intelligence-active" : "operational-intelligence-learning",
    score: Math.round((average + playbookReadiness + Math.max(0, 100 - openIssues * 8)) / 3),
    summary: "Operational Intelligence gives Nexus goals, playbooks, decision review, workflow recovery, outcome memory, and mission tracking across user, investor, and admin modes.",
    sourceTruth: "It uses AgriNexus records now and labels live provider results separately when external services are connected.",
    workflowScores: scores,
    playbookReadiness,
    openIssues,
    activeGoals,
    latestGoal: (intelligence.goals || [])[0] || null,
    latestIssue: (intelligence.issueReports || [])[0] || null,
    latestDecision: (intelligence.decisionReviews || [])[0] || null,
    latestPlaybookRun: (intelligence.playbookRuns || [])[0] || null,
    playbooks: (intelligence.playbooks || []).slice(0, 8),
    outcomeMemory: (intelligence.outcomeMemory || []).slice(0, 8),
    suggestedCommands: [
      "Nexus, create a goal to sell maize and track delivery",
      "Nexus, run the health access playbook",
      "Nexus, rank my next best step",
      "Nexus, this workflow is wrong",
      "Nexus, what is incomplete",
      "Nexus, run the crop sale playbook",
      "Nexus, help me recover the intake workflow",
      "Nexus, operational intelligence status"
    ]
  };
}

function operationalNextStepsForModule(module, text = "") {
  const lower = String(text || "").toLowerCase();
  const catalog = {
    Healthcare: ["Open a plain-language intake", "Search clinic/pharmacy support", "Prepare provider handoff", "Record follow-up and safety boundary"],
    Learning: ["Choose a course", "Open the lesson workspace", "Enable captions/audio support", "Record progress and certificate path"],
    Workforce: ["Build candidate profile", "Match role", "Submit application", "Prepare interview or shift support"],
    AgriTrade: ["Identify crop and buyer goal", "Find buyer/logistics support", "Create order", "Open route tracking and receipt path"],
    AgriTech: ["Capture field concern", "Run scan workflow", "Explain risk in simple language", "Create intervention task"],
    "Map & AI": ["Open full map", "Select route or area", "Explain risk and distance", "Save map evidence"],
    Platform: ["Clarify the goal", "Pick the best module", "Run the next safe workflow", "Record evidence"]
  };
  const steps = catalog[module] || catalog.Platform;
  if (/\b(emergency|danger|bleeding|can't breathe|cannot breathe|unconscious)\b/.test(lower)) {
    return ["Tell the user to contact local emergency help now", "Record this as urgent navigation support", "Prepare caregiver/provider handoff", "Do not diagnose"];
  }
  return steps;
}

function createOperationalGoal(db, user, body = {}) {
  const intelligence = ensureOperationalIntelligenceProfile(db.profile);
  const goalText = String(body.goal || body.title || body.query || "Help this user complete the next AgriNexus workflow").trim();
  const module = body.module || operationalModuleFromText(goalText);
  const scores = operationalWorkflowScores(db);
  const moduleScore = scores.find(item => item.module === module)?.percent || scores.find(item => module.includes(item.module))?.percent || 0;
  const goal = {
    id: crypto.randomUUID(),
    goalNumber: `NEX-GOAL-${String((intelligence.goals || []).length + 1).padStart(3, "0")}`,
    title: goalText,
    module,
    status: "active",
    owner: user.email,
    userName: user.name,
    completionScore: moduleScore,
    nextSteps: operationalNextStepsForModule(module, goalText),
    evidence: [`${module} workflow score ${moduleScore}%`, "Goal stored in Nexus operational memory"],
    source: "nexus-operational-intelligence",
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString()
  };
  intelligence.goals.unshift(goal);
  intelligence.goals = intelligence.goals.slice(0, 60);
  intelligence.outcomeMemory.unshift({ id: crypto.randomUUID(), type: "goal", summary: `${goal.goalNumber}: ${goal.title}`, module, status: "active", createdAt: goal.createdAt });
  intelligence.outcomeMemory = intelligence.outcomeMemory.slice(0, 80);
  rememberAgentMemory(db.profile, `Operational goal created: ${goal.title}. Next step: ${goal.nextSteps[0]}.`, { source: "operational-intelligence", category: "goal", module, confidence: 0.91 });
  addActivity(db.profile, `${goal.goalNumber} created: ${goal.title}.`);
  logIntegration(db, {
    providerId: "operational-intelligence",
    module,
    action: "operational.goal_created",
    status: "success",
    detail: `${goal.goalNumber} created for ${module}: ${goal.title}.`,
    metadata: { goal },
    dispatch: false
  });
  return goal;
}

function selectOperationalPlaybook(db, type = "", text = "") {
  const intelligence = ensureOperationalIntelligenceProfile(db.profile);
  const lower = `${type} ${text}`.toLowerCase();
  const playbooks = intelligence.playbooks || [];
  const explicit = playbooks.find(item => item.id === type);
  if (explicit) return explicit;
  if (/\b(doctor|clinic|medicine|pharmacy|health|intake|mobile clinic)\b/.test(lower)) return playbooks.find(item => item.id === "health-access");
  if (/\b(sell|buyer|crop|shipment|trade|delivery|order|payment)\b/.test(lower)) return playbooks.find(item => item.id === "crop-sale");
  if (/\b(learn|course|lesson|certificate|caption|student)\b/.test(lower)) return playbooks.find(item => item.id === "learning-path");
  if (/\b(job|work|apply|role|shift|interview)\b/.test(lower)) return playbooks.find(item => item.id === "workforce-placement");
  if (/\b(drone|field|scan|crop health|pest|soil)\b/.test(lower)) return playbooks.find(item => item.id === "field-intelligence");
  if (/\b(investor|proof|evidence|status|readiness)\b/.test(lower)) return playbooks.find(item => item.id === "investor-proof");
  return playbooks[0];
}

function runOperationalPlaybook(db, user, type = "", body = {}) {
  const intelligence = ensureOperationalIntelligenceProfile(db.profile);
  const request = String(body.request || body.goal || body.query || type || "Run operational playbook").trim();
  const playbook = selectOperationalPlaybook(db, type, request);
  const goal = createOperationalGoal(db, user, { goal: request, module: playbook?.module || operationalModuleFromText(request) });
  const run = {
    id: crypto.randomUUID(),
    runNumber: `NEX-PLAY-${String((intelligence.playbookRuns || []).length + 1).padStart(3, "0")}`,
    playbookId: playbook?.id || "general",
    title: playbook?.title || "General operational playbook",
    module: playbook?.module || goal.module,
    request,
    goalId: goal.id,
    status: "completed-local",
    steps: (playbook?.steps || goal.nextSteps || []).map((title, index) => ({ id: `${playbook?.id || "general"}-${index + 1}`, title, status: index === 0 ? "started" : "ready", order: index + 1 })),
    outcome: playbook?.plainOutcome || "Nexus created an operational path and next steps.",
    guardrail: playbook?.guardrail || "External actions remain labeled until live providers are connected.",
    createdBy: user.email,
    createdAt: new Date().toISOString()
  };
  intelligence.playbookRuns.unshift(run);
  intelligence.playbookRuns = intelligence.playbookRuns.slice(0, 60);
  intelligence.outcomeMemory.unshift({ id: crypto.randomUUID(), type: "playbook", summary: `${run.runNumber}: ${run.title}`, module: run.module, status: run.status, createdAt: run.createdAt });
  intelligence.outcomeMemory = intelligence.outcomeMemory.slice(0, 80);
  rememberAgentMemory(db.profile, `Operational playbook ran: ${run.title}. Outcome: ${run.outcome}.`, { source: "operational-playbook", category: "pattern", module: run.module, confidence: 0.93 });
  addActivity(db.profile, `${run.runNumber} completed: ${run.title}.`);
  logIntegration(db, {
    providerId: "operational-intelligence",
    module: run.module,
    action: "operational.playbook_run",
    status: "success",
    detail: `${run.runNumber} ran ${run.title}.`,
    metadata: { run },
    dispatch: false
  });
  return { run, goal };
}

function recordOperationalIssue(db, user, body = {}) {
  const intelligence = ensureOperationalIntelligenceProfile(db.profile);
  const detail = String(body.detail || body.issue || body.query || "User reported a workflow issue").trim();
  const module = body.module || operationalModuleFromText(detail);
  const issue = {
    id: crypto.randomUUID(),
    issueNumber: `NEX-FIX-${String((intelligence.issueReports || []).length + 1).padStart(3, "0")}`,
    module,
    detail,
    status: "guided-recovery",
    severity: /\b(can't|cannot|broken|wrong|not working|blank|stuck|freeze|partial|missing)\b/i.test(detail) ? "high" : "standard",
    recoverySteps: [
      "Stop the current explanation and acknowledge the issue",
      `Open the ${module} workflow from the top of the screen`,
      "Show one clear next action instead of a long explanation",
      "Record the issue for admin/investor review"
    ],
    createdBy: user.email,
    createdAt: new Date().toISOString()
  };
  intelligence.issueReports.unshift(issue);
  intelligence.issueReports = intelligence.issueReports.slice(0, 80);
  intelligence.feedbackLoops.unshift({ id: crypto.randomUUID(), issueId: issue.id, module, status: "active", nextAction: issue.recoverySteps[1], createdAt: issue.createdAt });
  intelligence.feedbackLoops = intelligence.feedbackLoops.slice(0, 80);
  rememberAgentMemory(db.profile, `User reported ${module} issue: ${detail}. Nexus should recover with fewer words and a visible action.`, { source: "workflow-issue", category: "correction", module, confidence: 0.97 });
  addActivity(db.profile, `${issue.issueNumber} recorded for ${module}: ${detail}.`);
  logIntegration(db, {
    providerId: "operational-intelligence",
    module,
    action: "operational.issue_recorded",
    status: "needs-review",
    detail: `${issue.issueNumber}: ${detail}`,
    metadata: { issue },
    dispatch: false
  });
  return issue;
}

function operationalDecisionReview(db, user, query = "") {
  const intelligence = ensureOperationalIntelligenceProfile(db.profile);
  const module = operationalModuleFromText(query);
  const directoryType = module === "Healthcare" ? "clinic"
    : module === "Learning" ? "course"
    : module === "Workforce" ? "job"
    : module === "AgriTrade" ? "buyer"
    : module === "AgriTech" ? "drone"
    : "";
  const directory = directoryType ? platformIntelligenceSearch(db, user, query, { type: directoryType }) : { matches: [] };
  const smart = smartNextActions(db, user).items || [];
  const workflowScore = operationalWorkflowScores(db).find(item => item.module === module)?.percent || 0;
  const choices = [
    ...(directory.matches || []).slice(0, 3).map((item, index) => ({
      rank: index + 1,
      title: item.name,
      source: "saved-local-directory",
      reason: item.service,
      confidence: Math.min(96, 72 + Number(item.score || 0) * 4)
    })),
    ...smart.filter(item => !module || item.module === module || module.includes(item.module)).slice(0, 3).map((item, index) => ({
      rank: (directory.matches || []).slice(0, 3).length + index + 1,
      title: item.title,
      source: "smart-next-actions",
      reason: item.detail,
      confidence: Math.min(92, 66 + workflowScore / 3)
    }))
  ].slice(0, 5);
  const review = {
    id: crypto.randomUUID(),
    reviewNumber: `NEX-DEC-${String((intelligence.decisionReviews || []).length + 1).padStart(3, "0")}`,
    query,
    module,
    workflowScore,
    bestChoice: choices[0] || { title: "Clarify the goal", source: "conversation", reason: "Nexus needs one more detail to rank the next step.", confidence: 60 },
    choices,
    explanation: choices[0]
      ? `Best next step for ${module}: ${choices[0].title}. Source: ${choices[0].source}.`
      : `I need one more detail before ranking choices for ${module}.`,
    createdBy: user.email,
    createdAt: new Date().toISOString()
  };
  intelligence.decisionReviews.unshift(review);
  intelligence.decisionReviews = intelligence.decisionReviews.slice(0, 60);
  intelligence.confidenceEvents.unshift({ id: crypto.randomUUID(), module, confidence: review.bestChoice.confidence, reason: review.bestChoice.reason, createdAt: review.createdAt });
  intelligence.confidenceEvents = intelligence.confidenceEvents.slice(0, 80);
  rememberAgentMemory(db.profile, `Decision review ${review.reviewNumber}: ${review.explanation}`, { source: "operational-decision", category: "decision", module, confidence: (review.bestChoice.confidence || 70) / 100 });
  logIntegration(db, {
    providerId: "operational-intelligence",
    module,
    action: "operational.decision_review",
    status: "success",
    detail: review.explanation,
    metadata: { review },
    dispatch: false
  });
  return review;
}

function operationalIntelligenceCommandResponse(db, user, text, options = {}) {
  const lower = String(text || "").toLowerCase();
  const operationalSignal = /\b(operational intelligence|goal|playbook|what is incomplete|incomplete|decision review|rank|best next step|workflow is wrong|wrong workflow|needs adjustment|not working|recover|issue|fix this|correct this|track my goal|mission status|outcome)\b/.test(lower);
  if (!operationalSignal) return null;
  if (/\b(workflow is wrong|wrong workflow|needs adjustment|not working|recover|issue|fix this|correct this|map needs|intake.*wrong|button.*wrong|blank|stuck|partial)\b/.test(lower)) {
    const issue = recordOperationalIssue(db, user, { detail: text });
    return {
      intent: "operational_intelligence.issue_recorded",
      status: "guided-recovery",
      response: `I recorded ${issue.issueNumber} for ${issue.module}. I will keep it simple: ${issue.recoverySteps[1]}.`,
      metadata: { conversationMode: true, redirectSection: conversationModuleSignal(text).section || "agent", operationalIntelligence: true, issue }
    };
  }
  if (/\b(playbook|run health|run crop|run learning|run workforce|run field|run investor|run proof)\b/.test(lower)) {
    const selected = /\bhealth|doctor|clinic|medicine|pharmacy\b/.test(lower) ? "health-access"
      : /\bcrop|sell|buyer|trade|shipment|delivery\b/.test(lower) ? "crop-sale"
      : /\blearn|course|lesson|certificate\b/.test(lower) ? "learning-path"
      : /\bjob|work|workforce|apply|shift\b/.test(lower) ? "workforce-placement"
      : /\bdrone|field|scan\b/.test(lower) ? "field-intelligence"
      : /\binvestor|proof|evidence\b/.test(lower) ? "investor-proof"
      : "";
    const result = runOperationalPlaybook(db, user, selected, { request: text });
    return {
      intent: "operational_intelligence.playbook_run",
      status: "completed",
      response: `${result.run.title} is running. First step: ${result.run.steps[0]?.title || "start"}. ${result.run.guardrail}`,
      metadata: { conversationMode: true, redirectSection: conversationModuleSignal(text).section || "agent", operationalIntelligence: true, run: result.run, goal: result.goal }
    };
  }
  if (/\b(decision review|rank|best next step|best option|what should i do next)\b/.test(lower)) {
    const review = operationalDecisionReview(db, user, text);
    return {
      intent: "operational_intelligence.decision_reviewed",
      status: "completed",
      response: review.explanation,
      metadata: { conversationMode: true, redirectSection: conversationModuleSignal(text).section || "agent", operationalIntelligence: true, review }
    };
  }
  if (/\b(create|track|start|save|remember).*\b(goal|mission|outcome)\b/.test(lower) || /\b(goal to|track my goal)\b/.test(lower)) {
    const cleaned = text.replace(/\b(nexus|create|track|start|save|remember|goal|mission|outcome|to|for)\b/gi, " ").replace(/\s+/g, " ").trim() || text;
    const goal = createOperationalGoal(db, user, { goal: cleaned });
    return {
      intent: "operational_intelligence.goal_created",
      status: "completed",
      response: `${goal.goalNumber} is active for ${goal.module}. Next: ${goal.nextSteps[0]}.`,
      metadata: { conversationMode: true, redirectSection: conversationModuleSignal(goal.title).section || "agent", operationalIntelligence: true, goal }
    };
  }
  const model = operationalIntelligenceModel(db, user);
  return {
    intent: "operational_intelligence.status",
    status: "completed",
    response: `Operational intelligence is ${model.status} at ${model.score}%. Open issues: ${model.openIssues}. Strongest next step: ${model.latestDecision?.bestChoice?.title || model.suggestedCommands[0]}.`,
    metadata: { conversationMode: true, redirectSection: "agent", operationalIntelligence: true, model }
  };
}

function ensureAdaptiveAutonomyProfile(profile) {
  ensureOperationalIntelligenceProfile(profile);
  profile.adaptiveAutonomy = profile.adaptiveAutonomy || {};
  const autonomy = profile.adaptiveAutonomy;
  autonomy.monitoringRuns = autonomy.monitoringRuns || [];
  autonomy.proactiveNudges = autonomy.proactiveNudges || [];
  autonomy.learningUpdates = autonomy.learningUpdates || [];
  autonomy.autonomousActions = autonomy.autonomousActions || [];
  autonomy.watchlist = autonomy.watchlist || [];
  autonomy.escalations = autonomy.escalations || [];
  autonomy.userPatterns = autonomy.userPatterns || [];
  autonomy.preventionRules = autonomy.preventionRules || [
    { id: "health-safety", title: "Health safety boundary", rule: "Do not diagnose, prescribe, or replace licensed care. For urgent danger, guide to local emergency help.", module: "Healthcare", status: "active" },
    { id: "money-guard", title: "Money movement guard", rule: "Do not complete real payment, payout, or transaction fee without live provider confirmation and user approval.", module: "AgriTrade", status: "active" },
    { id: "external-send-guard", title: "External communication guard", rule: "Draft and stage messages automatically; live SMS, WhatsApp, email, or phone sending depends on configured provider credentials.", module: "Communications", status: "active" },
    { id: "gps-provider-truth", title: "Location truth guard", rule: "Use local route evidence until live GPS/geocoding/logistics provider data is available.", module: "Map & AI", status: "active" },
    { id: "plain-language-first", title: "Plain-language recovery", rule: "When user confusion or low-tech context is detected, use one short step, ask one question, and avoid technical terms.", module: "AI", status: "active" }
  ];
  return autonomy;
}

function adaptiveModuleSection(module = "Platform") {
  if (/health/i.test(module)) return "health";
  if (/learn/i.test(module)) return "learning";
  if (/work/i.test(module)) return "workforce";
  if (/trade|agri|drone/i.test(module)) return "trade";
  if (/map/i.test(module)) return "map";
  return "agent";
}

function buildAdaptiveSignals(db, user, providers = runtimeProviders(db)) {
  const autonomy = ensureAdaptiveAutonomyProfile(db.profile);
  const operational = operationalIntelligenceModel(db, user);
  const signals = [];
  const now = Date.now();
  const addSignal = (type, module, title, detail, priority = "medium", action = "Review next step", confidence = 0.78) => {
    signals.push({
      id: crypto.randomUUID(),
      type,
      module,
      section: adaptiveModuleSection(module),
      title,
      detail,
      priority,
      action,
      confidence,
      createdAt: new Date().toISOString()
    });
  };
  (operational.workflowScores || []).forEach(score => {
    if (Number(score.percent || 0) < 75) {
      addSignal(
        "workflow-gap",
        score.module,
        `${score.module} needs follow-through`,
        `${score.evidence}. Completion is ${score.percent}%, so Nexus should guide the next visible action.`,
        Number(score.percent || 0) < 35 ? "high" : "medium",
        (operationalNextStepsForModule(score.module) || [])[0] || "Open workflow"
      );
    }
  });
  (operational.activeGoals || []).forEach(goal => {
    const ageHours = Math.round((now - Date.parse(goal.updatedAt || goal.createdAt || new Date().toISOString())) / 3600000);
    if (ageHours >= 12 || Number(goal.completionScore || 0) < 70) {
      addSignal(
        "goal-needs-progress",
        goal.module,
        `${goal.goalNumber} needs progress`,
        `${goal.title}. Current completion ${goal.completionScore || 0}%.`,
        ageHours >= 24 ? "high" : "medium",
        (goal.nextSteps || [])[0] || "Move the goal forward",
        0.86
      );
    }
  });
  const latestIssue = operational.latestIssue;
  if (latestIssue && !["resolved", "closed"].includes(latestIssue.status)) {
    addSignal(
      "recovery-needed",
      latestIssue.module,
      `${latestIssue.issueNumber} is still open`,
      latestIssue.detail,
      latestIssue.severity === "high" ? "high" : "medium",
      (latestIssue.recoverySteps || [])[1] || "Open recovery path",
      0.94
    );
  }
  const disconnectedProviders = providers.filter(provider => provider.status !== "connected").length;
  if (disconnectedProviders) {
    addSignal(
      "provider-gap",
      "Integrations",
      "Live provider gaps remain",
      `${disconnectedProviders} provider slot(s) are not fully connected. Nexus should label local vs live evidence clearly.`,
      "medium",
      "Show provider truth before action",
      0.82
    );
  }
  if (!(db.profile.healthIntakes || []).length) {
    addSignal("missing-intake", "Healthcare", "No health intake yet", "Telehealth can be stronger if Nexus opens a plain-language intake record.", "medium", "Start intake");
  }
  if (!(db.profile.orders || []).length) {
    addSignal("missing-trade-order", "AgriTrade", "No crop order yet", "Crop sale demos become stronger when an order, route, receipt, and buyer message exist.", "medium", "Create crop order");
  }
  if (!(db.profile.enrollments || []).length) {
    addSignal("missing-learning-path", "Learning", "No active learner path yet", "Learning feels stronger when a learner is enrolled and a next lesson is visible.", "medium", "Start course");
  }
  if (!(db.profile.applications || []).length) {
    addSignal("missing-workforce-path", "Workforce", "No job application yet", "Workforce feels stronger when a candidate profile and application are visible.", "medium", "Apply for role");
  }
  const unique = [];
  const seen = new Set();
  for (const signal of signals.sort((a, b) => ({ high: 3, medium: 2, low: 1 }[b.priority] || 0) - ({ high: 3, medium: 2, low: 1 }[a.priority] || 0))) {
    const key = `${signal.type}:${signal.module}`;
    if (!seen.has(key)) {
      seen.add(key);
      unique.push(signal);
    }
  }
  autonomy.watchlist = unique.slice(0, 12);
  return autonomy.watchlist;
}

function createAdaptiveNudge(db, user, signalOrBody = {}) {
  const autonomy = ensureAdaptiveAutonomyProfile(db.profile);
  const signal = signalOrBody.title ? signalOrBody : buildAdaptiveSignals(db, user)[0] || {};
  const module = signal.module || signalOrBody.module || "Platform";
  const nudge = {
    id: crypto.randomUUID(),
    nudgeNumber: `NEX-AUTO-${String((autonomy.proactiveNudges || []).length + 1).padStart(3, "0")}`,
    module,
    section: adaptiveModuleSection(module),
    title: signal.title || signalOrBody.title || "Nexus proactive next step",
    message: signal.detail || signalOrBody.message || "Nexus found a useful next step and prepared a simple prompt.",
    nextAction: signal.action || signalOrBody.nextAction || "Ask one question and guide the user forward",
    priority: signal.priority || signalOrBody.priority || "medium",
    status: "ready",
    sourceSignalId: signal.id || null,
    createdBy: user.email,
    createdAt: new Date().toISOString()
  };
  autonomy.proactiveNudges.unshift(nudge);
  autonomy.proactiveNudges = autonomy.proactiveNudges.slice(0, 80);
  addNotification(db.profile, {
    module,
    providerId: "adaptive-autonomy",
    channel: "in-app",
    message: `${nudge.nudgeNumber}: ${nudge.nextAction}`,
    createdBy: "Nexus"
  });
  rememberAgentMemory(db.profile, `Adaptive nudge created for ${module}: ${nudge.nextAction}.`, { source: "adaptive-autonomy", category: "proactive", module, confidence: 0.9 });
  logIntegration(db, {
    providerId: "adaptive-autonomy",
    module,
    action: "adaptive.nudge_created",
    status: "success",
    detail: `${nudge.nudgeNumber}: ${nudge.title}.`,
    metadata: { nudge },
    dispatch: false
  });
  return nudge;
}

function runAdaptiveAutonomyCycle(db, user, body = {}) {
  const autonomy = ensureAdaptiveAutonomyProfile(db.profile);
  const providers = runtimeProviders(db);
  const signals = buildAdaptiveSignals(db, user, providers);
  const nudges = signals.slice(0, Number(body.limit || 5)).map(signal => createAdaptiveNudge(db, user, signal));
  const run = {
    id: crypto.randomUUID(),
    runNumber: `NEX-LOOP-${String((autonomy.monitoringRuns || []).length + 1).padStart(3, "0")}`,
    mode: "controlled-adaptive-autonomy",
    status: "completed-local",
    summary: `${signals.length} signal(s) inspected and ${nudges.length} proactive nudge(s) prepared.`,
    signals: signals.slice(0, 10),
    nudges: nudges.map(nudge => ({ id: nudge.id, nudgeNumber: nudge.nudgeNumber, module: nudge.module, nextAction: nudge.nextAction })),
    guardrails: (autonomy.preventionRules || []).map(rule => rule.title),
    createdBy: user.email,
    createdAt: new Date().toISOString()
  };
  autonomy.monitoringRuns.unshift(run);
  autonomy.monitoringRuns = autonomy.monitoringRuns.slice(0, 50);
  autonomy.autonomousActions.unshift({
    id: crypto.randomUUID(),
    actionNumber: `NEX-ACT-${String((autonomy.autonomousActions || []).length + 1).padStart(3, "0")}`,
    type: "monitor-and-nudge",
    status: "completed-local",
    detail: run.summary,
    requiresApprovalForExternalAction: true,
    createdAt: run.createdAt
  });
  autonomy.autonomousActions = autonomy.autonomousActions.slice(0, 80);
  addActivity(db.profile, `${run.runNumber} adaptive autonomy cycle completed.`);
  addUsageEvent(db.profile, { module: "AI", action: "adaptive.autonomy_cycle", detail: run.summary, user: user.email });
  logIntegration(db, {
    providerId: "adaptive-autonomy",
    module: "AI",
    action: "adaptive.autonomy_cycle",
    status: "success",
    detail: run.summary,
    metadata: { runNumber: run.runNumber, signalCount: signals.length, nudgeCount: nudges.length },
    dispatch: false
  });
  return { run, signals, nudges };
}

function recordAdaptiveLearning(db, user, body = {}) {
  const autonomy = ensureAdaptiveAutonomyProfile(db.profile);
  const lesson = String(body.lesson || body.feedback || body.detail || "User preference recorded for adaptive behavior").trim();
  const module = body.module || operationalModuleFromText(lesson);
  const update = {
    id: crypto.randomUUID(),
    updateNumber: `NEX-LEARN-${String((autonomy.learningUpdates || []).length + 1).padStart(3, "0")}`,
    module,
    lesson,
    behaviorChange: String(body.behaviorChange || "Use shorter responses, ask one question, and open the most relevant workflow first.").trim(),
    status: "learned-local",
    createdBy: user.email,
    createdAt: new Date().toISOString()
  };
  autonomy.learningUpdates.unshift(update);
  autonomy.learningUpdates = autonomy.learningUpdates.slice(0, 80);
  autonomy.userPatterns.unshift({ id: crypto.randomUUID(), module, pattern: lesson, responseStyle: update.behaviorChange, createdAt: update.createdAt });
  autonomy.userPatterns = autonomy.userPatterns.slice(0, 80);
  rememberAgentMemory(db.profile, `Adaptive learning update: ${lesson}. Behavior change: ${update.behaviorChange}.`, { source: "adaptive-learning", category: "preference", module, confidence: 0.95 });
  logIntegration(db, {
    providerId: "adaptive-autonomy",
    module,
    action: "adaptive.learning_recorded",
    status: "success",
    detail: `${update.updateNumber}: ${lesson}`,
    metadata: { update },
    dispatch: false
  });
  return update;
}

function adaptiveAutonomyModel(db, user, providers = runtimeProviders(db)) {
  const autonomy = ensureAdaptiveAutonomyProfile(db.profile);
  const operational = operationalIntelligenceModel(db, user);
  const signals = buildAdaptiveSignals(db, user, providers);
  const high = signals.filter(signal => signal.priority === "high").length;
  const providerConnected = providers.filter(provider => provider.status === "connected").length;
  const score = Math.max(1, Math.min(100, Math.round(
    45
    + Math.min(20, (autonomy.learningUpdates || []).length * 4)
    + Math.min(20, (autonomy.monitoringRuns || []).length * 5)
    + Math.min(15, (autonomy.proactiveNudges || []).length * 2)
    + Math.min(10, providerConnected)
    - Math.min(25, high * 5)
  )));
  return {
    status: score >= 80 ? "adaptive-autonomous-active" : score >= 60 ? "adaptive-autonomous-learning" : "adaptive-autonomous-ready",
    score,
    summary: "Adaptive Autonomous Intelligence lets Nexus monitor goals, learn user patterns, prepare proactive nudges, catch stale workflows, and guide the next best action with safety guardrails.",
    autonomyBoundary: "Nexus can monitor, nudge, draft, remember, and prepare local workflow actions automatically. Real provider dispatch, payments, clinical decisions, external messages, and live GPS still require credentials and/or approval.",
    operationalScore: operational.score,
    activeSignals: signals.slice(0, 8),
    latestRun: (autonomy.monitoringRuns || [])[0] || null,
    latestNudge: (autonomy.proactiveNudges || [])[0] || null,
    latestLearning: (autonomy.learningUpdates || [])[0] || null,
    preventionRules: (autonomy.preventionRules || []).slice(0, 8),
    proactiveNudges: (autonomy.proactiveNudges || []).slice(0, 8),
    learningUpdates: (autonomy.learningUpdates || []).slice(0, 6),
    autonomousActions: (autonomy.autonomousActions || []).slice(0, 8),
    suggestedCommands: [
      "Nexus, run adaptive autonomy",
      "Nexus, monitor my goals",
      "Nexus, what should happen next automatically",
      "Nexus, learn that I need shorter answers",
      "Nexus, watch my crop sale",
      "Nexus, watch my health intake",
      "Nexus, create a proactive nudge",
      "Nexus, adaptive autonomy status"
    ]
  };
}

function adaptiveAutonomyCommandResponse(db, user, text, options = {}) {
  const lower = String(text || "").toLowerCase();
  const adaptiveSignal = /\b(adaptive autonomy|adaptive autonomous|autonomous intelligence|monitor my goals|watch my|proactive|nudge|learn that|remember that|what should happen next automatically|run adaptive|autonomy status|auto monitor|keep an eye)\b/.test(lower);
  if (!adaptiveSignal) return null;
  if (/\b(learn that|remember that|adapt|from now on|i prefer|i need shorter|too much talking|talk less|explain simply)\b/.test(lower)) {
    const update = recordAdaptiveLearning(db, user, { lesson: text });
    return {
      intent: "adaptive_autonomy.learning_recorded",
      status: "completed",
      response: `Learned. ${update.behaviorChange}`,
      metadata: { conversationMode: true, redirectSection: "agent", adaptiveAutonomy: true, update }
    };
  }
  if (/\b(nudge|remind|prompt|proactive)\b/.test(lower) && !/\b(run adaptive|monitor)\b/.test(lower)) {
    const signal = buildAdaptiveSignals(db, user).find(item => lower.includes(String(item.module || "").toLowerCase())) || buildAdaptiveSignals(db, user)[0] || {};
    const nudge = createAdaptiveNudge(db, user, signal);
    return {
      intent: "adaptive_autonomy.nudge_created",
      status: "completed",
      response: `${nudge.nudgeNumber} is ready. ${nudge.nextAction}.`,
      metadata: { conversationMode: true, redirectSection: nudge.section || "agent", adaptiveAutonomy: true, nudge }
    };
  }
  if (/\b(run adaptive|monitor|watch my|keep an eye|what should happen next automatically|auto monitor)\b/.test(lower)) {
    const result = runAdaptiveAutonomyCycle(db, user, { request: text });
    const first = result.nudges[0];
    return {
      intent: "adaptive_autonomy.cycle_completed",
      status: "completed",
      response: `${result.run.runNumber} complete. I found ${result.signals.length} signal(s). First next step: ${first?.nextAction || "nothing urgent right now"}.`,
      metadata: { conversationMode: true, redirectSection: first?.section || "agent", adaptiveAutonomy: true, run: result.run, signals: result.signals, nudges: result.nudges }
    };
  }
  const model = adaptiveAutonomyModel(db, user);
  return {
    intent: "adaptive_autonomy.status",
    status: "completed",
    response: `Adaptive autonomy is ${model.status} at ${model.score}%. Top signal: ${model.activeSignals[0]?.title || "no urgent signal"}.`,
    metadata: { conversationMode: true, redirectSection: "agent", adaptiveAutonomy: true, model }
  };
}

function ensureNetworkedIntelligenceProfile(profile) {
  ensureAdaptiveAutonomyProfile(profile);
  profile.networkIntelligence = profile.networkIntelligence || {};
  const network = profile.networkIntelligence;
  network.queries = network.queries || [];
  network.providerRoutes = network.providerRoutes || [];
  network.actionReadiness = network.actionReadiness || [];
  network.countryMatches = network.countryMatches || [];
  network.serviceRegistry = network.serviceRegistry || [];
  network.sourceAudits = network.sourceAudits || [];
  network.liveGaps = network.liveGaps || [];
  return network;
}

function networkServiceRegistry(providers = []) {
  const statusFor = id => providers.find(provider => provider.id === id) || { id, status: "needs-credentials", mode: "not-configured", detail: "Provider slot not found." };
  const registry = [
    { id: "internet-brain", title: "Live internet brain", module: "AI", providerIds: ["web-search", "openai"], keywords: ["current", "today", "latest", "internet", "price", "weather", "news", "market", "question"], countries: ["Pan-African", "Nigeria", "DRC", "Kenya", "Egypt", "Ghana", "Rwanda", "Tanzania", "South Africa"], localFallback: "Open dialog, platform records, and saved local directory." },
    { id: "maps-routing", title: "Maps, geocoding, and routing", module: "Map & AI", providerIds: ["maps", "routing-geocoding"], keywords: ["map", "route", "closest", "near", "location", "gps", "track", "directions", "shipment"], countries: ["Pan-African", "Nigeria", "DRC", "Kenya", "Egypt", "Ghana", "Rwanda", "Tanzania", "South Africa"], localFallback: "Saved route context, OpenStreetMap tiles when enabled, and local route evidence." },
    { id: "health-network", title: "Clinic, mobile clinic, pharmacy, and EHR network", module: "Healthcare", providerIds: ["health-telehealth", "health-ehr", "health-openmrs", "health-notifications"], keywords: ["doctor", "clinic", "mobile clinic", "pharmacy", "medicine", "patient", "provider", "intake", "ehr"], countries: ["Kenya", "Nigeria", "DRC", "Egypt", "Ghana", "Rwanda", "Tanzania", "South Africa", "Pan-African"], localFallback: "Local clinic/pharmacy records, safety-bounded intake, provider handoff drafts, and mobile clinic workflow." },
    { id: "learning-network", title: "Course catalog and certificate network", module: "Learning", providerIds: ["learning-lms", "learning-courses", "learning-certificates"], keywords: ["course", "learn", "lesson", "certificate", "training", "catalog", "student"], countries: ["Pan-African", "Kenya", "Nigeria", "Ghana", "Rwanda", "Tanzania", "South Africa", "Egypt", "DRC"], localFallback: "Local AgriNexus course catalog, progress, quiz, accessibility, and certificate evidence." },
    { id: "workforce-network", title: "Jobs, workforce, and shift network", module: "Workforce", providerIds: ["workforce-job-search", "workforce-jobs", "workforce-calendar", "workforce-hris", "workforce-shifts"], keywords: ["job", "work", "role", "apply", "shift", "interview", "worker", "hiring"], countries: ["Kenya", "Nigeria", "Ghana", "Rwanda", "Tanzania", "South Africa", "Egypt", "DRC", "Pan-African"], localFallback: "Local job records, profile build, application workflow, interview prep, mentor, and shift simulation." },
    { id: "trade-market-network", title: "Buyer, seller, market price, payment, and logistics network", module: "AgriTrade", providerIds: ["trade-market", "trade-logistics", "trade-payments", "billing-subscriptions"], keywords: ["buyer", "seller", "sell", "crop", "maize", "cassava", "price", "order", "payment", "receipt", "delivery", "shipment"], countries: ["Kenya", "Nigeria", "Ghana", "Rwanda", "Tanzania", "South Africa", "Egypt", "DRC", "Pan-African"], localFallback: "Local buyer desk, order workflow, route evidence, wallet/receipt path, and buyer/seller communication." },
    { id: "field-drone-network", title: "Drone, satellite, and field intelligence network", module: "AgriTech", providerIds: ["drones", "satellite-field-data", "maps"], keywords: ["drone", "field", "scan", "satellite", "crop health", "soil", "pest", "harvest", "yield"], countries: ["Pan-African", "Kenya", "Nigeria", "Ghana", "Rwanda", "Tanzania", "South Africa", "Egypt", "DRC"], localFallback: "Local drone mission, scan packet, field intervention, and simple farmer explanation." },
    { id: "communications-network", title: "Phone, SMS, WhatsApp, and email network", module: "Communications", providerIds: ["phone-voice", "sms-delivery", "whatsapp-delivery", "email-delivery"], keywords: ["call", "phone", "sms", "whatsapp", "message", "email", "notify", "contact", "speak"], countries: ["Pan-African", "Kenya", "Nigeria", "DRC", "Egypt", "Ghana", "Rwanda", "Tanzania", "South Africa"], localFallback: "In-app thread, message drafts, phone prompt, and notification record until live delivery is configured." }
  ];
  return registry.map(service => {
    const serviceProviders = service.providerIds.map(statusFor);
    const connected = serviceProviders.filter(provider => provider.status === "connected");
    const ready = connected.length > 0;
    return {
      ...service,
      providers: serviceProviders.map(provider => ({ id: provider.id, name: provider.name || provider.id, status: provider.status, mode: provider.mode, detail: provider.detail })),
      connectedCount: connected.length,
      providerCount: serviceProviders.length,
      status: ready ? "live-capable" : "local-fallback",
      sourceLabel: ready ? "live-provider-capable" : "local-platform-fallback",
      confidence: ready ? Math.min(98, 74 + connected.length * 6) : 58,
      nextCredential: serviceProviders.find(provider => provider.status !== "connected")?.id || ""
    };
  });
}

function networkIntentFromText(text = "") {
  const lower = String(text || "").toLowerCase();
  if (/\b(doctor|clinic|medicine|pharmacy|patient|health|telehealth|mobile clinic|provider|ehr|intake)\b/.test(lower)) return "health-network";
  if (/\b(course|learn|lesson|training|certificate|catalog|student)\b/.test(lower)) return "learning-network";
  if (/\b(job|work|role|apply|shift|interview|worker|hiring)\b/.test(lower)) return "workforce-network";
  if (/\b(buyer|seller|sell|crop|maize|cassava|price|order|payment|receipt|delivery|shipment|market)\b/.test(lower)) return "trade-market-network";
  if (/\b(drone|field|scan|satellite|crop health|soil|pest|harvest|yield)\b/.test(lower)) return "field-drone-network";
  if (/\b(map|route|closest|near me|near|location|gps|track|directions)\b/.test(lower)) return "maps-routing";
  if (/\b(call|phone|sms|whatsapp|message|email|notify|contact|speak)\b/.test(lower)) return "communications-network";
  if (/\b(current|today|latest|internet|weather|news|question)\b/.test(lower)) return "internet-brain";
  return "internet-brain";
}

function networkCountryFromText(text = "", db = null) {
  const lower = String(text || "").toLowerCase();
  const countries = ["Nigeria", "DRC", "Congo", "Kenya", "Egypt", "Ghana", "Rwanda", "Tanzania", "South Africa", "Ethiopia", "Brazil"];
  const found = countries.find(country => lower.includes(country.toLowerCase()));
  if (found === "Congo") return "DRC";
  if (found) return found;
  if (db) return activeContext(db).country.name || "Pan-African";
  return "Pan-African";
}

function networkProviderMatch(db, user, query = "", options = {}) {
  const providers = runtimeProviders(db);
  const registry = networkServiceRegistry(providers);
  const intentId = options.serviceId || networkIntentFromText(query);
  const country = options.country || networkCountryFromText(query, db);
  const service = registry.find(item => item.id === intentId) || registry[0];
  const localSearchType = service.id === "health-network" ? (/\b(pharmacy|medicine)\b/i.test(query) ? "pharmacy" : "clinic")
    : service.id === "learning-network" ? "course"
    : service.id === "workforce-network" ? "job"
    : service.id === "trade-market-network" ? "buyer"
    : service.id === "field-drone-network" ? "drone"
    : service.id === "maps-routing" ? "logistics"
    : "";
  const localResult = localSearchType ? platformIntelligenceSearch(db, user, query || service.title, { type: localSearchType, country }) : { matches: [] };
  const topProvider = service.providers.find(provider => provider.status === "connected") || service.providers[0] || {};
  const sourceLabel = service.connectedCount ? "live-provider-capable" : localResult.matches?.length ? "saved-local-directory" : "local-platform-fallback";
  const confidence = Math.max(service.confidence || 50, localResult.matches?.length ? 70 : 0);
  const match = {
    id: crypto.randomUUID(),
    query,
    serviceId: service.id,
    serviceTitle: service.title,
    module: service.module,
    country,
    status: service.status,
    sourceLabel,
    sourceTruth: service.connectedCount
      ? `Nexus found ${service.connectedCount} connected provider path(s). External results still depend on provider terms, coverage, and request approval.`
      : `Nexus can run local AgriNexus workflow evidence now. Live external results need credentials for: ${service.providerIds.join(", ")}.`,
    confidence,
    topProvider,
    connectedProviders: service.providers.filter(provider => provider.status === "connected"),
    providerOptions: service.providers,
    localFallback: service.localFallback,
    localMatches: (localResult.matches || []).slice(0, 5),
    actionReadiness: networkActionReadiness(db, service, query),
    createdAt: new Date().toISOString()
  };
  return match;
}

function networkActionReadiness(db, serviceOrId, query = "") {
  const providers = runtimeProviders(db);
  const registry = networkServiceRegistry(providers);
  const service = typeof serviceOrId === "string" ? registry.find(item => item.id === serviceOrId) : serviceOrId;
  const selected = service || registry.find(item => item.id === networkIntentFromText(query)) || registry[0];
  const live = (selected.providers || []).filter(provider => provider.status === "connected");
  const guardedActions = [];
  if (/health/i.test(selected.module)) guardedActions.push("No diagnosis or prescription. Prepare intake and licensed-provider handoff only.");
  if (/trade/i.test(selected.module)) guardedActions.push("No real payment, payout, or transaction fee without live payment provider and approval.");
  if (/communication/i.test(selected.module)) guardedActions.push("No external SMS, WhatsApp, email, or call without configured provider and recipient.");
  if (/map/i.test(selected.module) || /agritech/i.test(selected.module)) guardedActions.push("Label local route or field evidence until live GPS, drone, satellite, or geocoding data is connected.");
  return {
    serviceId: selected.id,
    serviceTitle: selected.title,
    module: selected.module,
    status: live.length ? "live-capable" : "local-workflow-ready",
    confidence: live.length ? Math.min(96, 76 + live.length * 5) : 62,
    canDoNow: [
      `Route the request to ${selected.module}`,
      "Search saved AgriNexus records",
      "Open the matching workflow",
      "Draft or stage the next action",
      "Record source truth and audit evidence"
    ],
    needsLiveProviderFor: live.length ? [] : [
      "Current external data",
      "Real provider inventory or availability",
      "Real dispatch, payment, GPS, or partner-system updates"
    ],
    guardrails: guardedActions.length ? guardedActions : ["Use source labels and ask for confirmation before external actions."],
    providerIds: selected.providerIds,
    connectedProviderIds: live.map(provider => provider.id)
  };
}

function runNetworkIntelligenceQuery(db, user, body = {}) {
  const network = ensureNetworkedIntelligenceProfile(db.profile);
  const query = String(body.query || body.command || "Find the best real-world provider path").trim();
  const match = networkProviderMatch(db, user, query, body);
  const record = {
    id: crypto.randomUUID(),
    queryNumber: `NEX-NET-${String((network.queries || []).length + 1).padStart(3, "0")}`,
    query,
    serviceId: match.serviceId,
    serviceTitle: match.serviceTitle,
    module: match.module,
    country: match.country,
    status: match.status,
    sourceLabel: match.sourceLabel,
    sourceTruth: match.sourceTruth,
    confidence: match.confidence,
    topProviderId: match.topProvider?.id || "",
    localFallback: match.localFallback,
    localMatches: match.localMatches,
    actionReadiness: match.actionReadiness,
    createdBy: user.email,
    createdAt: match.createdAt
  };
  network.queries.unshift(record);
  network.queries = network.queries.slice(0, 80);
  network.providerRoutes.unshift({
    id: crypto.randomUUID(),
    queryId: record.id,
    module: record.module,
    providerId: record.topProviderId || "local-fallback",
    status: record.status,
    sourceLabel: record.sourceLabel,
    createdAt: record.createdAt
  });
  network.providerRoutes = network.providerRoutes.slice(0, 80);
  network.sourceAudits.unshift({ id: crypto.randomUUID(), queryId: record.id, sourceLabel: record.sourceLabel, sourceTruth: record.sourceTruth, confidence: record.confidence, createdAt: record.createdAt });
  network.sourceAudits = network.sourceAudits.slice(0, 80);
  rememberAgentMemory(db.profile, `Network intelligence query ${record.queryNumber}: ${query}. Source ${record.sourceLabel}.`, { source: "network-intelligence", category: "provider-routing", module: record.module, confidence: record.confidence / 100 });
  logIntegration(db, {
    providerId: "network-intelligence",
    module: record.module,
    action: "network.query_routed",
    status: "success",
    detail: `${record.queryNumber} routed to ${record.serviceTitle}: ${record.sourceLabel}.`,
    metadata: { record },
    dispatch: false
  });
  addActivity(db.profile, `${record.queryNumber} network query routed: ${record.serviceTitle}.`);
  return { record, match };
}

function networkCountryCoverageModel(db, providers = runtimeProviders(db)) {
  const registry = networkServiceRegistry(providers);
  const countries = ["Nigeria", "DRC", "Kenya", "Egypt", "Ghana", "Rwanda", "Tanzania", "South Africa", "Pan-African"];
  return countries.map(country => {
    const services = registry.filter(service => (service.countries || []).includes(country));
    const liveCapable = services.filter(service => service.status === "live-capable").length;
    return {
      country,
      serviceCount: services.length,
      liveCapable,
      localFallback: services.length - liveCapable,
      status: liveCapable ? "partly-live" : "local-ready",
      plainAnswer: liveCapable
        ? `${country} has ${liveCapable} live-capable service lane(s) and local fallback for the rest.`
        : `${country} can run local AgriNexus workflows now; live providers are still needed for current external data.`
    };
  });
}

function networkIntelligenceModel(db, user, providers = runtimeProviders(db)) {
  const network = ensureNetworkedIntelligenceProfile(db.profile);
  const registry = networkServiceRegistry(providers);
  const liveServices = registry.filter(service => service.status === "live-capable").length;
  const score = Math.min(100, Math.round(42 + liveServices * 6 + Math.min(20, (network.queries || []).length * 2) + Math.min(16, (network.providerRoutes || []).length * 2)));
  network.serviceRegistry = registry.map(service => ({ id: service.id, title: service.title, status: service.status, connectedCount: service.connectedCount, providerCount: service.providerCount, sourceLabel: service.sourceLabel }));
  network.liveGaps = registry.filter(service => service.status !== "live-capable").map(service => ({ id: service.id, title: service.title, providerIds: service.providerIds, nextCredential: service.nextCredential }));
  network.countryMatches = networkCountryCoverageModel(db, providers);
  return {
    status: liveServices ? "network-intelligence-partly-live" : "network-intelligence-local-ready",
    score,
    summary: "Network Intelligence gives Nexus a provider-aware outside-world routing layer for clinics, pharmacies, jobs, courses, buyers, logistics, maps, weather, drone/satellite data, payments, phone, SMS, WhatsApp, and live internet search.",
    sourceTruth: "Every answer is labeled as live-provider-capable, saved-local-directory, or local-platform-fallback so investors and users know what is real now and what needs credentials.",
    registry: network.serviceRegistry,
    liveServices,
    totalServices: registry.length,
    latestQuery: (network.queries || [])[0] || null,
    latestRoute: (network.providerRoutes || [])[0] || null,
    liveGaps: network.liveGaps,
    countryCoverage: network.countryMatches,
    suggestedCommands: [
      "Nexus, use network intelligence to find the closest clinic in Kenya",
      "Nexus, check current maize market price in Kenya",
      "Nexus, find live job providers for farm work",
      "Nexus, route my crop shipment from Kenya to Nigeria",
      "Nexus, find medicine support near Nairobi",
      "Nexus, check weather before harvest",
      "Nexus, find drone or satellite field support",
      "Nexus, network intelligence status"
    ]
  };
}

function networkIntelligenceCommandResponse(db, user, text, options = {}) {
  const lower = String(text || "").toLowerCase();
  const networkSignal = /\b(network intelligence|networked intelligence|live provider|real provider|provider network|outside world|current|today|latest|closest|near me|market price|weather|live job|live course|live clinic|live pharmacy|route my crop|track.*shipment|internet brain)\b/.test(lower);
  if (!networkSignal) return null;
  if (/\b(status|readiness|what is connected|what providers|network intelligence)\b/.test(lower) && !/\b(find|route|price|weather|closest|near|track|check)\b/.test(lower)) {
    const model = networkIntelligenceModel(db, user);
    return {
      intent: "network_intelligence.status",
      status: "completed",
      response: `Network intelligence is ${model.status} at ${model.score}%. Live-capable service lanes: ${model.liveServices}/${model.totalServices}.`,
      metadata: { conversationMode: true, redirectSection: "integrations", networkIntelligence: true, model }
    };
  }
  const result = runNetworkIntelligenceQuery(db, user, { query: text });
  const record = result.record;
  const local = record.localMatches?.[0];
  const wantsMap = /\b(map|route|track|tracking|shipment|gps|location|where|near me|closest|nearest)\b/.test(lower);
  const section = wantsMap ? "map" : adaptiveModuleSection(record.module);
  const moduleSignal = {
    module: section === "map" ? "Maps" : record.module,
    section,
    score: 3,
    source: "network-intelligence"
  };
  const frontierCommunication = frontierCommunicationIntelligenceModel(text, moduleSignal, user, options);
  const liveText = record.status === "live-capable"
    ? `I found a live-ready path for ${record.serviceTitle}.`
    : `I can guide this now with saved AgriNexus information; real-time outside listings need the live credentials.`;
  const fallback = local ? ` I found ${local.name}.` : ` I can use ${record.localFallback}.`;
  const nextQuestion = section === "map"
    ? "Where should I start the map from?"
    : frontierCommunication.nextQuestion;
  return {
    intent: "network_intelligence.query_routed",
    status: record.status,
    response: `${liveText} Source: ${record.sourceLabel}.${fallback} ${nextQuestion}`,
    metadata: { conversationMode: true, redirectSection: section, networkIntelligence: true, record, match: result.match, moduleSignal, frontierCommunication }
  };
}

function ensureEcosystemIntelligenceProfile(profile) {
  ensureNetworkedIntelligenceProfile(profile);
  profile.ecosystemIntelligence = profile.ecosystemIntelligence || {};
  const ecosystem = profile.ecosystemIntelligence;
  ecosystem.missions = ecosystem.missions || [];
  ecosystem.graphNodes = ecosystem.graphNodes || [];
  ecosystem.graphEdges = ecosystem.graphEdges || [];
  ecosystem.readinessAudits = ecosystem.readinessAudits || [];
  ecosystem.outcomes = ecosystem.outcomes || [];
  ecosystem.coordinationRuns = ecosystem.coordinationRuns || [];
  return ecosystem;
}

