function providerCandidateCatalog(db, providers = runtimeProviders(db)) {
  ensureOperationsProfile(db.profile);
  const runtimeById = Object.fromEntries(providers.map(provider => [provider.id, provider]));
  const shortlistById = Object.fromEntries((db.profile.providerShortlist || []).map(item => [item.candidateId, item]));
  const packetsByType = {};
  for (const packet of db.profile.providerPartnerships || []) {
    if (!packetsByType[packet.type]) packetsByType[packet.type] = packet;
  }
  const candidates = REAL_PROVIDER_CANDIDATES.map(candidate => {
    const runtime = runtimeById[candidate.providerId] || {};
    const packet = packetsByType[candidate.partnershipType];
    const shortlisted = shortlistById[candidate.id];
    const apiReady = ["api-available", "enterprise-api"].includes(candidate.apiStatus);
    return {
      ...candidate,
      runtimeStatus: runtime.status || "needs-provider-selection",
      runtimeMode: runtime.mode || "candidate",
      runtimeDetail: runtime.detail || "Provider slot is ready; choose vendor credentials or partnership.",
      apiReady,
      shortlisted: Boolean(shortlisted),
      shortlistStatus: shortlisted?.status || "not-shortlisted",
      packetStatus: packet?.status || "not-started",
      packetId: packet?.id || null,
      readiness: runtime.status === "connected" ? "connected" : apiReady ? "ready-for-credentials" : "partnership-needed"
    };
  });
  const groups = providerCandidateGroups().map(group => {
    const groupCandidates = candidates.filter(candidate => candidate.category === group.id);
    const topCandidates = groupCandidates.slice(0, 4);
    return {
      ...group,
      count: groupCandidates.length,
      readyNow: groupCandidates.filter(candidate => candidate.apiReady).length,
      partnershipNeeded: groupCandidates.filter(candidate => !candidate.apiReady).length,
      shortlisted: groupCandidates.filter(candidate => candidate.shortlisted).length,
      runtimeStatus: runtimeById[group.providerId]?.status || "needs-provider-selection",
      runtimeMode: runtimeById[group.providerId]?.mode || "candidate",
      topCandidates,
      candidates: groupCandidates
    };
  });
  const countryCoverage = providerCandidateCountryCoverage(candidates, groups);
  return {
    total: candidates.length,
    readyNow: candidates.filter(candidate => candidate.apiReady).length,
    partnershipNeeded: candidates.filter(candidate => !candidate.apiReady).length,
    shortlisted: candidates.filter(candidate => candidate.shortlisted).length,
    focus: {
      audience: "Rural African farmers and farming families",
      operatingModel: "Voice-first, low-bandwidth, multilingual, phone-friendly support for crop sales, field advice, health access, learning, workforce, logistics, and payments.",
      countryPriority: ["Nigeria", "DRC", "Kenya", "Egypt", "Ghana", "Rwanda", "Tanzania", "Uganda", "South Africa", "pan-African partners"],
      mustWorkFor: ["smallholder farmers", "cooperatives", "rural elders", "low-literacy users", "hearing-impaired users", "visually-impaired users", "field agents"],
      successDefinition: "A farmer can speak to Nexus, sell a crop, understand field risk, contact support, track delivery, learn a skill, and get health or workforce help without needing technical training."
    },
    countryCoverage,
    groups,
    candidates,
    nextBestActions: [
      "Shortlist one provider per category.",
      "Create partner packets for the shortlisted categories.",
      "Add vendor URLs/API keys in Render when credentials are approved.",
      "Run live service check after each provider is connected."
    ]
  };
}

function providerCandidateCountryCoverage(candidates, groups) {
  const countries = [
    { id: "nigeria", name: "Nigeria", region: "West Africa", priority: "high", strengths: ["payments", "marketplace", "learning", "voice-first farmer support"] },
    { id: "drc", name: "DRC", region: "Central Africa", priority: "high", strengths: ["telehealth access", "field intelligence", "route risk", "mobile money partner search"] },
    { id: "kenya", name: "Kenya", region: "East Africa", priority: "high", strengths: ["agritech partners", "mobile money", "learning", "logistics"] },
    { id: "egypt", name: "Egypt", region: "North Africa", priority: "high", strengths: ["irrigation", "field intelligence", "learning", "provider partnerships"] },
    { id: "ghana", name: "Ghana", region: "West Africa", priority: "high", strengths: ["payments", "marketplace", "learning", "farmer cooperatives"] },
    { id: "rwanda", name: "Rwanda", region: "East Africa", priority: "high", strengths: ["digital public services", "telehealth partner search", "learning", "field agents"] },
    { id: "tanzania", name: "Tanzania", region: "East Africa", priority: "high", strengths: ["smallholder farms", "mobile money", "logistics", "field intelligence"] },
    { id: "south-africa", name: "South Africa", region: "Southern Africa", priority: "high", strengths: ["provider networks", "health booking", "payments", "logistics"] },
    { id: "pan-africa", name: "Pan-African", region: "Multi-country", priority: "platform-wide", strengths: ["shared provider bridge", "voice AI", "translation", "satellite/drone data", "farmer marketplace expansion"] }
  ];
  const countrySpecific = {
    nigeria: ["tavily", "brave-search", "mapbox", "openrouteservice", "moodle", "adzuna", "openmrs", "sentinel-hub-direct", "flutterwave", "paystack", "pawapay", "terminal-africa", "useri", "zowasel", "eosda", "sentinel-hub", "udemy-business", "ulesson", "country-health-privacy-counsel", "data-protection-officer", "clinical-governance-review"],
    drc: ["tavily", "openrouteservice", "moodle", "adzuna", "openmrs", "sentinel-hub-direct", "pawapay", "eosda", "sentinel-hub", "leaf-agriculture", "ithalamed", "sentros", "udemy-business", "local-employer-network", "country-health-privacy-counsel", "data-protection-officer", "clinical-governance-review"],
    kenya: ["tavily", "brave-search", "mapbox", "openrouteservice", "moodle", "adzuna", "openmrs", "sentinel-hub-direct", "pawapay", "flutterwave", "terminal-africa", "furaha", "eosda", "sentinel-hub", "ulesson", "local-employer-network", "country-health-privacy-counsel", "data-protection-officer", "clinical-governance-review"],
    egypt: ["tavily", "exa-search", "mapbox", "openrouteservice", "moodle", "openedx", "adzuna", "openmrs", "sentinel-hub-direct", "eosda", "sentinel-hub", "leaf-agriculture", "udemy-business", "pluralsight-skills", "ithalamed", "local-employer-network", "country-health-privacy-counsel", "data-protection-officer", "clinical-governance-review"],
    ghana: ["tavily", "brave-search", "mapbox", "openrouteservice", "moodle", "adzuna", "openmrs", "sentinel-hub-direct", "flutterwave", "paystack", "pawapay", "terminal-africa", "zowasel", "eosda", "ulesson", "local-employer-network", "country-health-privacy-counsel", "data-protection-officer", "clinical-governance-review"],
    rwanda: ["tavily", "openrouteservice", "moodle", "adzuna", "openmrs", "sentinel-hub-direct", "pawapay", "eosda", "sentinel-hub", "ithalamed", "sentros", "ulesson", "local-employer-network", "country-health-privacy-counsel", "data-protection-officer", "clinical-governance-review"],
    tanzania: ["tavily", "openrouteservice", "moodle", "adzuna", "openmrs", "sentinel-hub-direct", "pawapay", "terminal-africa", "furaha", "eosda", "sentinel-hub", "ulesson", "local-employer-network", "country-health-privacy-counsel", "data-protection-officer", "clinical-governance-review"],
    "south-africa": ["tavily", "brave-search", "mapbox", "openrouteservice", "moodle", "openedx", "adzuna", "openmrs", "sentinel-hub-direct", "recomed", "paystack", "flutterwave", "terminal-africa", "eosda", "sentinel-hub", "pluralsight-skills", "local-employer-network", "country-health-privacy-counsel", "data-protection-officer", "clinical-governance-review"],
    "pan-africa": candidates.map(candidate => candidate.id)
  };
  const categoryTitles = Object.fromEntries(groups.map(group => [group.id, group.title]));
  return countries.map(country => {
    const selected = (countrySpecific[country.id] || []).map(id => candidates.find(candidate => candidate.id === id)).filter(Boolean);
    const categories = [...new Set(selected.map(candidate => candidate.category))].map(category => ({
      id: category,
      title: categoryTitles[category] || category,
      candidates: selected.filter(candidate => candidate.category === category).slice(0, 4).map(candidate => ({
        id: candidate.id,
        name: candidate.name,
        readiness: candidate.readiness,
        apiStatus: candidate.apiStatus,
        providerId: candidate.providerId
      }))
    }));
    const missingCategories = groups
      .filter(group => !categories.some(category => category.id === group.id))
      .map(group => group.title);
    return {
      ...country,
      status: missingCategories.length ? "needs-local-partner-selection" : "candidate-covered",
      providerCount: selected.length,
      categories,
      missingCategories,
      plainAnswer: missingCategories.length
        ? `${country.name} has candidate coverage for ${categories.length} engine area(s); local partners are still needed for ${missingCategories.slice(0, 3).join(", ")}.`
        : `${country.name} has candidate coverage across the rural farmer operating model. Live use still requires credentials, contracts, and country validation.`,
      farmerUseCase: `In ${country.name}, Nexus should help a rural farmer ask for crop advice, sell crops, track delivery, reach health support, learn skills, and find work with country-aware provider choices.`
    };
  });
}

function shortlistProviderCandidate(db, user, candidateId) {
  ensureOperationsProfile(db.profile);
  const catalog = providerCandidateCatalog(db);
  const candidate = catalog.candidates.find(item => item.id === candidateId);
  if (!candidate) return null;
  const now = new Date().toISOString();
  let record = db.profile.providerShortlist.find(item => item.candidateId === candidate.id);
  if (!record) {
    record = {
      id: crypto.randomUUID(),
      candidateId: candidate.id,
      name: candidate.name,
      category: candidate.category,
      module: candidate.module,
      providerId: candidate.providerId,
      partnershipType: candidate.partnershipType,
      website: candidate.website,
      status: "shortlisted",
      nextAction: candidate.nextAction,
      createdBy: user.email,
      createdAt: now,
      updatedAt: now
    };
    db.profile.providerShortlist.unshift(record);
  } else {
    record.status = "shortlisted";
    record.nextAction = candidate.nextAction;
    record.updatedAt = now;
  }
  db.profile.providerShortlist = db.profile.providerShortlist.slice(0, 50);
  logIntegration(db, {
    providerId: candidate.providerId,
    module: candidate.module,
    action: "provider.candidate_shortlisted",
    detail: `${candidate.name} shortlisted for ${candidate.module}: ${candidate.bestUse}`,
    metadata: { candidateId: candidate.id, category: candidate.category, website: candidate.website, credentials: candidate.credentials },
    dispatch: false
  });
  addUsageEvent(db.profile, { module: "Integrations", action: "provider.candidate_shortlisted", detail: candidate.name, user: user.email });
  addActivity(db.profile, `${candidate.name} shortlisted as a real ${candidate.module} provider candidate.`);
  return record;
}

