async function createOutboundCallWorkflow(db, user, body = {}) {
  ensureAiProfile(db.profile);
  const purpose = String(body.purpose || body.context || body.module || "AgriNexus outbound support").trim();
  const recipient = outboundCallRecipientForPurpose(purpose, body);
  const message = String(body.message || `This is AgriNexus calling about ${purpose}. You can speak after the greeting and the AI assistant will help route the next step.`).trim();
  const delivery = await startTwilioOutboundCall({ to: recipient, message, context: purpose });
  const record = {
    id: crypto.randomUUID(),
    callNumber: `CALL-${String((db.profile.outboundCalls || []).length + 1).padStart(3, "0")}`,
    purpose,
    to: recipient || "",
    from: process.env.TWILIO_PHONE_NUMBER || "",
    message,
    status: delivery.ok ? "calling-live" : delivery.status,
    provider: "twilio",
    delivery,
    createdBy: user.email,
    createdAt: new Date().toISOString()
  };
  db.profile.outboundCalls = db.profile.outboundCalls || [];
  db.profile.outboundCalls.unshift(record);
  db.profile.outboundCalls = db.profile.outboundCalls.slice(0, 30);
  voiceRecord(db, user, "phone-call", delivery.ok ? `Outbound call started: ${purpose}` : `Outbound call needs setup: ${purpose}`, { callId: record.id, to: record.to, status: record.status, delivery });
  logIntegration(db, {
    providerId: "phone-voice",
    module: "AI",
    action: "phone.outbound_call_requested",
    status: delivery.ok ? "success" : "needs-setup",
    detail: delivery.ok ? `${record.callNumber} started to ${record.to}.` : `${record.callNumber} could not start. Missing/setup: ${(delivery.missing || [delivery.error || delivery.status]).join(", ")}.`,
    metadata: { callId: record.id, purpose, delivery },
    dispatch: false
  });
  addActivity(db.profile, delivery.ok ? `Outbound call started: ${purpose}` : `Outbound call prepared but needs setup: ${purpose}`);
  rememberAgentMemory(db.profile, `Outbound call workflow: ${purpose}, status ${record.status}.`, { source: "outbound-call", category: "communications", module: "AI", confidence: 0.9 });
  return record;
}

function xmlEscape(value) {
  return String(value || "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&apos;");
}

function twimlResponse(res, xml) {
  return send(res, 200, xml, { "content-type": "text/xml; charset=utf-8" });
}

function twilioLanguage(language) {
  return process.env.TWILIO_GATHER_LANGUAGE || voiceLocaleForLanguage(language);
}

function twilioSay(text, language) {
  return `<Say voice="${xmlEscape(process.env.TWILIO_TTS_VOICE || "alice")}" language="${xmlEscape(language)}">${xmlEscape(text)}</Say>`;
}

async function phoneVoicePrompt(text, language) {
  const fallback = twilioSay(text, language);
  if (!process.env.OPENAI_API_KEY || !process.env.PUBLIC_BASE_URL) return fallback;
  try {
    const audio = await openAiSpeechAudio({ text, voice: process.env.OPENAI_TTS_VOICE || "verse", responseFormat: "mp3" });
    if (!audio?.audioDataUrl) return fallback;
    const id = crypto.randomUUID();
    const base64 = audio.audioDataUrl.replace(/^data:audio\/[^;]+;base64,/, "");
    phoneAudioCache.set(id, {
      buffer: Buffer.from(base64, "base64"),
      createdAt: Date.now()
    });
    for (const [key, value] of phoneAudioCache.entries()) {
      if (Date.now() - value.createdAt > 10 * 60 * 1000) phoneAudioCache.delete(key);
    }
    const audioUrl = `${String(process.env.PUBLIC_BASE_URL).replace(/\/$/, "")}/api/voice/phone/audio/${id}.mp3`;
    return `<Play>${xmlEscape(audioUrl)}</Play>`;
  } catch {
    return fallback;
  }
}

function phoneVoiceUser(db) {
  return db.users.find(item => item.role === "Admin") || db.users[0];
}

function ensurePhoneVoiceSessions(profile) {
  ensureAiProfile(profile);
  profile.phoneVoiceSessions = profile.phoneVoiceSessions || [];
  return profile.phoneVoiceSessions;
}

function phoneSessionKey(body = {}, fallback = "") {
  return String(body.CallSid || body.callSid || body.From || body.from || fallback || "phone-session").slice(0, 120);
}

function getPhoneVoiceSession(db, key) {
  const sessions = ensurePhoneVoiceSessions(db.profile);
  let session = sessions.find(item => item.key === key);
  if (!session) {
    session = {
      id: crypto.randomUUID(),
      key,
      callerName: "",
      language: "",
      locale: "en-US",
      step: "name",
      commands: [],
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    };
    sessions.unshift(session);
    db.profile.phoneVoiceSessions = sessions.slice(0, 60);
  }
  return session;
}

function updatePhoneVoiceSession(db, session, patch = {}) {
  Object.assign(session, patch, { updatedAt: new Date().toISOString() });
  db.profile.phoneVoiceSessions = ensurePhoneVoiceSessions(db.profile).slice(0, 60);
  return session;
}

function extractCallerName(text = "") {
  const cleaned = String(text || "").trim().replace(/[^\p{L}\p{N}\s'-]/gu, " ").replace(/\s+/g, " ");
  const match = cleaned.match(/\b(?:my name is|i am|i'm|this is|it is|it's|call me|my names|mi nombre es|me llamo|soy|je m appelle|je suis|mon nom est|jina langu ni|naitwa|mimi ni|ana ismi|ismi)\s+([\p{L}][\p{L}'-]{1,30})/iu);
  const candidate = match ? match[1] : cleaned.split(/\s+/).find(word => /^[\p{L}][\p{L}'-]{1,30}$/u.test(word));
  if (!candidate) return "";
  return candidate.charAt(0).toUpperCase() + candidate.slice(1);
}

function phoneLanguageChoice(text = "") {
  const lower = String(text || "").toLowerCase();
  const choices = [
    { code: "en", locale: "en-US", label: "English", tests: ["english", "inglés", "anglais", "kiingereza"] },
    { code: "es", locale: "es-ES", label: "Spanish", tests: ["spanish", "espanol", "español", "castellano", "inglés no"] },
    { code: "fr", locale: "fr-FR", label: "French", tests: ["french", "français", "francais", "française"] },
    { code: "sw", locale: "sw-KE", label: "Kiswahili", tests: ["swahili", "kiswahili", "swa hili"] },
    { code: "ar", locale: "ar-EG", label: "Arabic", tests: ["arabic", "arabe", "عربي", "العربية"] },
    { code: "en", locale: "en-US", label: "English with Hausa fallback", tests: ["hausa"] },
    { code: "en", locale: "en-US", label: "English with Yoruba fallback", tests: ["yoruba"] },
    { code: "en", locale: "en-US", label: "English with Igbo fallback", tests: ["igbo", "ibo"] },
    { code: "en", locale: "en-US", label: "English with Amharic fallback", tests: ["amharic", "amhara"] },
    { code: "en", locale: "en-US", label: "English with Oromo fallback", tests: ["oromo"] },
    { code: "en", locale: "en-US", label: "English with Kinyarwanda fallback", tests: ["kinyarwanda", "rwanda"] },
    { code: "fr", locale: "fr-FR", label: "French with Lingala fallback", tests: ["lingala"] }
  ];
  return choices.find(choice => choice.tests.some(test => lower.includes(test))) || null;
}

function phoneAutoLanguageChoice(text = "") {
  const lower = String(text || "").toLowerCase();
  const choices = [
    { code: "en", locale: "en-US", label: "English", tests: ["english", "hello", "good morning", "good afternoon", "good evening", "my name is", "this is"] },
    { code: "es", locale: "es-ES", label: "Spanish", tests: ["spanish", "espanol", "castellano", "hola", "buenos dias", "buenas tardes", "buenas noches", "me llamo", "mi nombre es", "yo necesito"] },
    { code: "fr", locale: "fr-FR", label: "French", tests: ["french", "francais", "bonjour", "bonsoir", "salut", "je m appelle", "je suis", "mon nom est", "j ai besoin"] },
    { code: "sw", locale: "sw-KE", label: "Kiswahili", tests: ["swahili", "kiswahili", "jambo", "habari", "mambo", "naitwa", "jina langu", "ninahitaji"] },
    { code: "ar", locale: "ar-EG", label: "Arabic", tests: ["arabic", "arabe", "salaam", "salam", "marhaba", "ana ismi", "ismi"] },
    { code: "en", locale: "en-US", label: "English with Hausa fallback", tests: ["hausa", "sannu", "ina kwana", "sunana"] },
    { code: "en", locale: "en-US", label: "English with Yoruba fallback", tests: ["yoruba", "bawo", "ekaro", "oruko mi"] },
    { code: "en", locale: "en-US", label: "English with Igbo fallback", tests: ["igbo", "ibo", "ndewo", "ututu oma", "aha m"] },
    { code: "en", locale: "en-US", label: "English with Amharic fallback", tests: ["amharic", "amhara", "selam", "tena yistilign"] },
    { code: "en", locale: "en-US", label: "English with Oromo fallback", tests: ["oromo", "akkam", "maqaan koo"] },
    { code: "en", locale: "en-US", label: "English with Kinyarwanda fallback", tests: ["kinyarwanda", "rwanda", "muraho", "amakuru"] },
    { code: "fr", locale: "fr-FR", label: "French with Lingala fallback", tests: ["lingala", "mbote"] }
  ];
  return choices.find(choice => choice.tests.some(test => lower.includes(test))) || phoneLanguageChoice(text);
}

function phoneAutoLanguagePrompt(name = "", label = "English") {
  const greeting = name ? `Hello ${name}, how can I assist you? ` : "How can I assist you? ";
  return `${greeting}I heard ${label}, so I will use ${label}.`;
}

function phoneLanguagePrompt(name = "") {
  const prefix = name ? `Thank you, ${name}. ` : "";
  return `${prefix}What language should I use? Say English, Spanish, French, Swahili, or Arabic. If you say Hausa, Yoruba, Igbo, Amharic, Oromo, Kinyarwanda, or Lingala, I will use the closest English or French phone fallback.`;
}

function phoneCommandPrompt(name = "", label = "English") {
  const greeting = name ? `Hello ${name}, how can I assist you?` : "How can I assist you?";
  return `${greeting} I will use ${label}.`;
}

async function openAiTranscribeAudio({ audioBase64, mimeType = "audio/webm", filename = "agrinexus-voice.webm", language }) {
  if (!process.env.OPENAI_API_KEY || !audioBase64) return null;
  const bytes = Buffer.from(String(audioBase64).replace(/^data:[^,]+,/, ""), "base64");
  const form = new FormData();
  form.append("file", new Blob([bytes], { type: mimeType }), filename);
  form.append("model", process.env.OPENAI_TRANSCRIBE_MODEL || "gpt-4o-mini-transcribe");
  if (language) form.append("language", language);
  const response = await fetch("https://api.openai.com/v1/audio/transcriptions", {
    method: "POST",
    headers: { Authorization: `Bearer ${process.env.OPENAI_API_KEY}` },
    body: form
  });
  const payload = await response.json().catch(() => ({}));
  if (!response.ok) throw new Error(payload.error?.message || `OpenAI transcription failed: ${response.status}`);
  return {
    transcript: payload.text || "",
    provider: "openai-audio-transcriptions",
    model: process.env.OPENAI_TRANSCRIBE_MODEL || "gpt-4o-mini-transcribe"
  };
}

async function openAiSpeechAudio({ text, voice, responseFormat = "mp3" }) {
  if (!process.env.OPENAI_API_KEY) return null;
  const requestedVoice = voice || process.env.OPENAI_TTS_VOICE || "verse";
  const createSpeech = selectedVoice => fetch("https://api.openai.com/v1/audio/speech", {
    method: "POST",
    headers: {
      Authorization: `Bearer ${process.env.OPENAI_API_KEY}`,
      "Content-Type": "application/json"
    },
    body: JSON.stringify({
      model: process.env.OPENAI_TTS_MODEL || "gpt-4o-mini-tts",
      voice: selectedVoice,
      input: String(text || "").slice(0, 4096),
      response_format: responseFormat,
      instructions: process.env.OPENAI_TTS_INSTRUCTIONS || "Speak as Nexus, a warm and capable AI assistant. Sound natural, conversational, and reassuring. Use clear everyday language, a steady medium pace, short sentences, and light warmth. Avoid sounding slow, robotic, dramatic, like a radio announcer, or like a cartoon character."
    })
  });
  let response = await createSpeech(requestedVoice);
  let finalVoice = requestedVoice;
  if (!response.ok && requestedVoice !== "coral") {
    response = await createSpeech("coral");
    finalVoice = "coral";
  }
  if (!response.ok) {
    const payload = await response.json().catch(() => ({}));
    throw new Error(payload.error?.message || `OpenAI speech failed: ${response.status}`);
  }
  const buffer = Buffer.from(await response.arrayBuffer());
  return {
    audioDataUrl: `data:audio/${responseFormat};base64,${buffer.toString("base64")}`,
    provider: "openai-audio-speech",
    model: process.env.OPENAI_TTS_MODEL || "gpt-4o-mini-tts",
    voice: finalVoice
  };
}

function openAiRealtimeVoice() {
  return process.env.OPENAI_REALTIME_VOICE || process.env.OPENAI_TTS_VOICE || "marin";
}

function openAiRealtimeModel() {
  return process.env.OPENAI_REALTIME_MODEL || "gpt-realtime-2";
}

function openAiRealtimeInstructions(user, language = "en") {
  return process.env.OPENAI_REALTIME_INSTRUCTIONS || [
    "You are Nexus, the live voice companion inside AgriNexus.",
    `User: ${user?.displayName || user?.name || user?.email || "AgriNexus user"}. Preferred language code: ${language || "en"}.`,
    "Listen patiently to imperfect speech, accents, fragments, and mixed-language phrases.",
    "Answer like a calm human helper: short acknowledgement, simple guidance, then a clear next step.",
    "Support farmers, patients, learners, workers, administrators, investors, mobile clinics, pharmacies, crop trade, maps, logistics, and learning.",
    "For health, do not diagnose. Help with intake questions, safety guidance, clinic/pharmacy/mobile-clinic access, captions, and provider handoff.",
    "This Realtime session is conversational only. You cannot open screens, run tools, send messages, call providers, create records, or execute workflows from this channel.",
    "When the user asks for a platform action, explain that the browser Mic or typed Ask Nexus command must route it through AgriNexus workflow confirmation first.",
    "If the request is unclear, ask one simple question instead of listing a menu.",
    "If the user says stop, pause immediately and wait."
  ].join(" ");
}

function openAiRealtimeSessionConfig(user, language = "en") {
  return {
    type: "realtime",
    model: openAiRealtimeModel(),
    audio: {
      output: {
        voice: openAiRealtimeVoice()
      }
    },
    instructions: openAiRealtimeInstructions(user, language)
  };
}

async function openAiRealtimeSdpAnswer({ sdp, user, language = "en" }) {
  if (!process.env.OPENAI_API_KEY) throw new Error("OPENAI_API_KEY is required for OpenAI Realtime voice.");
  const session = openAiRealtimeSessionConfig(user, language);
  const form = new FormData();
  form.set("sdp", sdp);
  form.set("session", JSON.stringify(session));
  const safetyId = crypto
    .createHash("sha256")
    .update(String(user?.id || user?.email || "anonymous"))
    .digest("hex");
  const response = await fetchWithTimeout("https://api.openai.com/v1/realtime/calls", {
    method: "POST",
    headers: {
      Authorization: `Bearer ${process.env.OPENAI_API_KEY}`,
      "OpenAI-Safety-Identifier": safetyId
    },
    body: form
  }, Number(process.env.OPENAI_REALTIME_TIMEOUT_MS || 20000));
  const answer = await response.text();
  if (!response.ok) {
    let detail = answer;
    try {
      const payload = JSON.parse(answer);
      detail = payload.error?.message || answer;
    } catch {
      // Realtime can return text/plain errors; keep the raw answer.
    }
    throw new Error(detail || `OpenAI Realtime failed: ${response.status}`);
  }
  return {
    sdp: answer,
    provider: "openai-realtime-webrtc",
    model: session.model,
    voice: session.audio.output.voice
  };
}

