function voiceRecoveryResponse(db) {
  ensureAiProfile(db.profile);
  const context = lastWorkflowContext(db.profile);
  const routes = voiceRecoveryRoutes(context.section || "dashboard");
  const suggestions = routes.map(item => item.phrase);
  const recovery = {
    id: crypto.randomUUID(),
    section: context.section || "dashboard",
    contextIntent: context.intent || "",
    suggestions,
    routes,
    status: "waiting-answer",
    createdAt: new Date().toISOString()
  };
  db.profile.agentMemory.activeRecovery = recovery;
  db.profile.agentMemory.lastStatus = "voice-recovery";
  db.profile.agentMemory.lastSummary = `I caught part of that. Possible directions: ${suggestions.join(", or ")}.`;
  db.profile.agentMemory.updatedAt = recovery.createdAt;
  return {
    intent: "conversation.voice_recovery",
    response: `I caught part of that. Do you mean ${suggestions.join(", or ")}? Say it in your own words and I'll continue.`,
    status: "needs-input",
    metadata: { conversationMode: true, redirectSection: context.section || "agent", suggestions, recovery }
  };
}

function continueVoiceRecovery(db, user, command) {
  ensureAiProfile(db.profile);
  const recovery = db.profile.agentMemory.activeRecovery;
  if (!recovery) return null;
  const lower = String(command || "").toLowerCase();
  if (isNegativeCommand(lower)) {
    db.profile.agentMemory.activeRecovery = null;
    db.profile.agentMemory.lastStatus = "voice-recovery-canceled";
    db.profile.agentMemory.lastSummary = "Voice recovery canceled.";
    db.profile.agentMemory.updatedAt = new Date().toISOString();
    return {
      intent: "conversation.voice_recovery_canceled",
      response: "No problem. I stopped that recovery prompt. Tell me what you want in your own words.",
      status: "canceled",
      metadata: { conversationMode: true, redirectSection: recovery.section || "agent" }
    };
  }
  const route = (recovery.routes || []).find(item => lower.includes(String(item.phrase || "").toLowerCase()) || (item.keys || []).some(key => lower.includes(key)));
  if (!route) {
    db.profile.agentMemory.activeRecovery = null;
    db.profile.agentMemory.lastStatus = "voice-recovery-released";
    db.profile.agentMemory.lastSummary = "Voice recovery released because the user gave a different clear command.";
    db.profile.agentMemory.updatedAt = new Date().toISOString();
    return null;
  }
  const completed = {
    ...recovery,
    answer: command,
    selectedAction: route.action,
    selectedTool: route.tool,
    status: "resolved",
    resolvedAt: new Date().toISOString()
  };
  db.profile.agentMemory.recoveryHistory = [completed, ...(db.profile.agentMemory.recoveryHistory || [])].slice(0, 20);
  db.profile.agentMemory.activeRecovery = null;
  const staged = stageAgentAction(db, `Recovered voice command: ${command}`, {
    module: route.module,
    tool: route.tool,
    action: route.action,
    section: route.section,
    planner: "voice-recovery-router",
    confidence: 0.78,
    rationale: `User selected a recovery option after an unclear voice command.`
  });
  return {
    ...staged,
    intent: "conversation.voice_recovery_resolved",
    response: `Got it. I can ${route.action.toLowerCase()} now. Say "yes" to run it, or "no" to cancel.`,
    metadata: {
      ...(staged.metadata || {}),
      recovery: completed,
      suggestedReplies: ["yes", "no", "explain that"]
    }
  };
}

function conversationFollowUpResponse(db, user, text, lower) {
  ensureAiProfile(db.profile);
  const memory = db.profile.agentMemory;
  const pending = db.profile.agentPendingAction;
  const recommendation = memory.lastRecommendedAction || smartNextActions(db, user).items[0] || null;
  const context = lastWorkflowContext(db.profile);
  const wantsExplanation = /\b(explain|repeat|say that again|read that|what do you mean|why|summarize that)\b/.test(lower);
  const wantsMission = /\b(current mission|mission status|where are we|what are we doing|what step|where am i|orient me|checklist|guided mission)\b/.test(lower);
  const wantsNavigation = /\b(take me there|open that|show me|go there|go to it|where is that)\b/.test(lower);
  const wantsNext = /\b(continue|next step|do the next|run the next|start the next|do that|let's do that|lets do that|proceed)\b/.test(lower);
  if (!wantsExplanation && !wantsNavigation && !wantsNext && !wantsMission) return null;

  if (wantsMission) {
    const outcome = activeOutcomeLoopBrief(db);
    if (outcome && !/\b(checklist|guided mission)\b/.test(lower)) {
      return {
        intent: "conversation.outcome_loop_status",
        response: `${outcome.phrase}. Say ${outcome.sayNext} when you are ready, or say Nexus stop if I misunderstood.`,
        status: outcome.status || "completed",
        metadata: { conversationMode: true, redirectSection: outcome.section || "dashboard", outcomeLoop: outcome }
      };
    }
    const guided = /\b(checklist|guided mission)\b/.test(lower) ? activeGuidedMissionBrief(db) : null;
    if (guided) {
      return {
        intent: "conversation.guided_mission_status",
        response: `${guided.phrase}. Progress is ${guided.progress} percent. Say continue when you are ready.`,
        status: "completed",
        metadata: { conversationMode: true, redirectSection: guided.section || "dashboard", guidedMission: guided }
      };
    }
    const brief = activeVoiceMissionBrief(db);
    return {
      intent: "conversation.voice_mission_status",
      response: brief ? `${brief.phrase}. Progress is ${brief.progress} percent. Say continue when you are ready.` : "No active voice mission is running yet. Tell me what you want to accomplish, and I will guide it.",
      status: brief ? "completed" : "needs-input",
      metadata: { conversationMode: true, redirectSection: brief?.section || "dashboard", voiceMission: brief }
    };
  }

  if (wantsExplanation) {
    const detail = pending
      ? `The pending action is ${pending.action || "a workflow"} in ${pending.module || "AgriNexus"}. I am waiting because this action may create or change workflow evidence. Say yes to run it, or no to cancel.`
      : memory.lastSummary || "I do not have a recent answer to explain yet.";
    return {
      intent: "conversation.followup_explained",
      response: detail,
      status: pending ? "needs-confirmation" : "completed",
      metadata: { conversationMode: true, redirectSection: pending?.section || memory.lastRecommendedSection || context.section || "agent" }
    };
  }

  if (wantsNavigation && !wantsNext) {
    const section = pending?.section || recommendation?.section || memory.lastRecommendedSection || context.section || "dashboard";
    return {
      intent: "conversation.followup_navigate",
      response: `I am taking you to ${section}. From there, I can guide the next step by voice.`,
      status: "completed",
      metadata: { conversationMode: true, redirectSection: section, recommendation }
    };
  }

  if (pending && wantsNext) {
    return {
      intent: "conversation.followup_pending",
      response: `I already have ${pending.action || "a workflow"} ready. Say "yes" to run it, or "no" to cancel.`,
      status: "needs-confirmation",
      metadata: { conversationMode: true, redirectSection: pending.section || "agent", pendingActionId: pending.id }
    };
  }

  if (recommendation && wantsNext) {
    const agentAction = workflowActionToAgentAction(recommendation);
    if (agentAction) {
      const staged = stageAgentAction(db, text, {
        ...agentAction,
        planner: "follow-up-recommendation",
        confidence: recommendation.confidence || 0.82,
        rationale: recommendation.reason || recommendation.detail || "This was the last recommended next action."
      });
      memory.conversationQuality.stagedActions = Number(memory.conversationQuality.stagedActions || 0) + 1;
      return {
        ...staged,
        response: `Yes. The next best step is ${recommendation.title}. ${recommendation.detail} Say "yes" to run it, or "no" to cancel.`,
        metadata: { ...staged.metadata, recommendationId: recommendation.id, followUp: true }
      };
    }
    return {
      intent: "conversation.followup_navigate",
      response: `The next best step is ${recommendation.title}. I am opening ${recommendation.section || "dashboard"} so I can guide it with you.`,
      status: "completed",
      metadata: { conversationMode: true, redirectSection: recommendation.section || "dashboard", recommendation }
    };
  }

  return {
    intent: "conversation.followup_recovery",
    response: "I can continue, but I need one clear direction. Say open telehealth, start training, apply for a job, contact my buyer, run drone scan, or test engines.",
    status: "needs-input",
    metadata: { conversationMode: true, redirectSection: context.section || "dashboard" }
  };
}

function socialConversationResponse(db, user, text, lower) {
  ensureAiProfile(db.profile);
  if (/^(hi|hello|hey|good morning|good afternoon|good evening|are you there|can you hear me)\b/.test(lower)) {
    const name = db.profile.agentMemory.userModel?.name || user.name?.split(/\s+/)[0] || "there";
    db.profile.agentMemory.lastStatus = "conversation-ready";
    db.profile.agentMemory.lastSummary = `Hello ${name}. I am listening and ready to guide the next step.`;
    db.profile.agentMemory.updatedAt = new Date().toISOString();
    return {
      intent: "conversation.greeting",
      response: `Hello ${name}. I am here with you. Tell me what you want to do in plain language, and I will guide one step at a time.`,
      status: "completed",
      metadata: { conversationMode: true, redirectSection: db.profile.agentMemory.lastRecommendedSection || "dashboard" }
    };
  }
  if (/^(thanks|thank you|appreciate it|that helps|perfect|great|awesome)\b/.test(lower)) {
    const next = db.profile.agentMemory.lastRecommendedAction || smartNextActions(db, user).items[0];
    return {
      intent: "conversation.acknowledged",
      response: next
        ? `You're welcome. I am still here. The next thing I can help with is ${next.title}. Say "do the next step" when you are ready.`
        : "You're welcome. I am still here. Say what you want to do next and I will guide it.",
      status: "completed",
      metadata: { conversationMode: true, redirectSection: next?.section || "dashboard", recommendation: next || null }
    };
  }
  if (/^(wait|hold on|pause|give me a second|one second|stop talking)\b/.test(lower)) {
    db.profile.agentMemory.lastStatus = "paused-by-user";
    db.profile.agentMemory.lastSummary = "User asked AgriNexus to pause and wait.";
    db.profile.agentMemory.updatedAt = new Date().toISOString();
    return {
      intent: "conversation.paused",
      response: "No problem. I will wait. When you are ready, say continue or ask the next question.",
      status: "paused",
      metadata: { conversationMode: true, redirectSection: db.profile.agentMemory.lastRecommendedSection || "dashboard" }
    };
  }
  return null;
}

async function voiceInvestorDemo(db, user) {
  const goal = "Run a voice-led investor demo across learning, workforce, telehealth, AgriTrade, drones, maps, and provider readiness.";
  const { plan, execution } = await createAndExecuteAutopilotMission(db, user, goal, "Voice investor demo mode");
  const script = [
    "Welcome to AgriNexus. This is a voice-first operating system for rural learning, workforce readiness, accessible telehealth, agriculture trade, drone intelligence, live maps, and AI-guided operations.",
    "The assistant can guide a non-technical user from a spoken need to an actual workflow, with confirmation, evidence, and next steps.",
    "In this demo, AgriNexus creates training evidence, workforce movement, telehealth support, trade and buyer activity, drone field intelligence, route risk, and provider evidence."
  ].join(" ");
  db.profile.agentBriefings = db.profile.agentBriefings || [];
  db.profile.agentBriefings.unshift({ id: crypto.randomUUID(), title: "Voice Investor Demo", plainLanguageSummary: script, planId: plan.id, executionId: execution.id, createdBy: user.email, createdAt: new Date().toISOString() });
  logIntegration(db, { providerId: "openai", module: "AI", action: "agent.voice_demo_completed", detail: `Voice investor demo executed with ${execution.steps.length} step(s).`, metadata: { planId: plan.id, executionId: execution.id } });
  return { intent: "agent.voice_demo_mode", response: `${script} Demo evidence is complete: ${execution.summary}`, status: execution.status, metadata: { conversationMode: true, redirectSection: "agent", planId: plan.id, executionId: execution.id, steps: execution.steps.length } };
}

function localizedWorkflowPhrase(lower) {
  const normalized = String(lower || "").normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  const phrases = [
    { patterns: ["demarre telesante", "iniciar telesalud", "anza afya", "anza usajili"], command: "start telehealth intake" },
    { patterns: ["connecte moi", "conectame", "niunganishe"], command: "connect me to a provider" },
    { patterns: ["postuler", "solicitar trabajo", "omba kazi"], command: "apply for that job" },
    { patterns: ["terminer lecon", "completa mi leccion", "kamilisha somo"], command: "complete my lesson" },
    { patterns: ["contacter acheteur", "contacta comprador", "wasiliana na mnunuzi"], command: "contact my buyer" },
    { patterns: ["rapport acheteur", "actualizacion comprador", "taarifa kwa mnunuzi"], command: "AgriTrade prepare a buyer update" },
    { patterns: ["risque route", "riesgo ruta", "hatari ya njia"], command: "check my route risk" },
    { patterns: ["scan drone", "escaneo dron", "ukaguzi wa drone"], command: "run drone scan" }
  ];
  return phrases.find(item => item.patterns.some(pattern => normalized.includes(pattern)))?.command || "";
}

function normalizeSpeechForIntent(value = "") {
  return String(value || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^\p{L}\p{N}\s]/gu, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function hasSpeechSignal(text = "", signals = []) {
  const value = normalizeSpeechForIntent(text);
  return signals.some(signal => {
    if (signal instanceof RegExp) return signal.test(value);
    return value.includes(normalizeSpeechForIntent(signal));
  });
}

function resilientConversationIntent(db, user, rawText = "") {
  const text = normalizeSpeechForIntent(rawText);
  if (!text) return null;
  const guidedFrontier = (module, section, nextQuestion, urgency = "normal") => ({
    conversationMode: true,
    suppressBehaviorNudge: true,
    resilientSpeech: true,
    moduleSignal: { module, section },
    frontierCommunication: {
      urgency,
      nextQuestion,
      confidence: 0.94,
      responseShape: "acknowledge, route, guide, ask one simple next question"
    }
  });
  const metadataBase = guidedFrontier("Platform", "dashboard", "Tell me one word first: health, crops, work, learning, map, or medicine.");
  const has = signals => hasSpeechSignal(text, signals);
  const capabilitySignals = [
    /\bwhat can (?:you )?do\b/, /\bwhat you do\b/, /\byou can do what\b/, /\bhow help\b/,
    "que puedes hacer", "que haces", "que hace", "que peut tu faire", "que peux tu faire", "que fais tu",
    "unaweza kufanya nini", "unafanya nini", "o que voce pode fazer", "o que faz",
    "ماذا تفعل", "ماذا تستطيع", "ماذا يمكنك"
  ];
  const medicineSignals = [
    /\b(need|want|find|get|help)\s+(medicine|medication|pills|drug|refill|pharmacy)\b/,
    /\b(medicine|medication|pills|drug|refill|pharmacy)\s+(need|want|help|please|where)\b/,
    "dawa", "medicina", "medicamento", "remedio", "medicament", "medicaments", "pharmacie",
    "nahitaji dawa", "nina hitaji dawa", "necesito medicina", "preciso remedio",
    "دواء", "صيدلية", "ادوية", "أدوية"
  ];
  const clinicSignals = [
    /\b(clinic|hospital|health center|health centre)\s+(near|nearby|closest|where|find|map|please)\b/,
    /\b(near|nearby|closest|where|find|map)\s+(clinic|hospital|health center|health centre)\b/,
    "clinic near", "find clinic", "clinic please", "clinica cerca", "clinica", "clinique pres", "clinique",
    "kliniki karibu", "hospitali karibu", "عيادة", "مستشفى", "clinica perto"
  ];
  const doctorSignals = [
    /\b(need|want|see|call|talk|speak|find|help)\s+(doctor|nurse|provider|clinician)\b/,
    /\b(doctor|nurse|provider|clinician)\s+(need|please|help|call|where)\b/,
    "doctor please", "daktari", "medico", "medica", "docteur", "infirmier", "enfermera",
    "طبيب", "دكتور", "ممرض"
  ];
  const cropProblemSignals = [
    /\b(crop|farm|field|plant|maize|cassava|rice|beans|harvest|shamba)\s+(bad|sick|dying|yellow|dry|pest|bugs|problem|weak)\b/,
    /\b(bad|sick|dying|yellow|dry|pest|bugs|problem|weak)\s+(crop|farm|field|plant|maize|cassava|rice|beans|harvest|shamba)\b/,
    "crop bad", "farm bad", "maize yellow", "shamba mbaya", "mimea mbaya", "cultivo malo", "cosecha mala",
    "recolte mauvaise", "campo ruim", "محصول سيء", "زرع مريض"
  ];
  const cropSaleSignals = [
    /\b(sell|selling|market|buyer|trade)\s+(crop|maize|cassava|rice|beans|produce|harvest|product)\b/,
    /\b(crop|maize|cassava|rice|beans|produce|harvest|product)\s+(sell|buyer|market|trade)\b/,
    "sell crop", "buyer crop", "vender cosecha", "vendo cosecha", "vendre recolte", "kuuza mazao",
    "nataka kuuza", "بيع المحصول", "comprador", "acheteur", "mnunuzi"
  ];
  const workSignals = [
    /\b(need|want|find|looking|help)\s+(work|job|jobs|employment|role|paid work)\b/,
    /\b(work|job|jobs|employment|role|paid work)\s+(need|want|please|help|find)\b/,
    "job please", "work please", "kazi", "nataka kazi", "trabajo", "empleo", "travail", "emploi",
    "preciso trabalho", "عمل", "وظيفة"
  ];
  const learningSignals = [
    /\b(start|begin|open|take|need|want|help)\s+(course|lesson|training|class|learn|learning)\b/,
    /\b(course|lesson|training|class|learn|learning)\s+(start|begin|please|help|want|need)\b/,
    "teach me", "want learn", "i no understand lesson", "curso", "leccion", "cours", "lecon",
    "somo", "kujifunza", "aprender", "تعلم", "دورة"
  ];
  const mapSignals = [
    /\b(open|show|find|need|want)\s+(map|route|location|tracking)\b/,
    /\b(map|route|location|tracking)\s+(open|show|please|where|need)\b/,
    "open map", "map please", "show route", "mapa", "carte", "ramani", "rota", "خريطة", "طريق", "موقع"
  ];

  if (has(capabilitySignals) && !/\b(agritrade|agri trade|auto\s*pilot|autopilot)\b/.test(text) && has(["farmer", "farm", "smallholder", "grower"]) && !/\b(start to finish|end to end|safely|safe)\b/.test(text)) {
    return {
      intent: "conversation.farmer_help",
      response: "For a farmer, I can help check a bad crop, explain drone or field data, find a buyer, compare route risk, track a shipment, and prepare sale evidence. What crop and village should we start with?",
      status: "completed",
      metadata: { ...guidedFrontier("AgriTrade", "trade", "What crop and village should we start with?"), redirectSection: "trade", suggestedReplies: ["my crop is bad", "find a buyer", "track my shipment"] }
    };
  }
  if (has(capabilitySignals) && !/\b(agritrade|agri trade)\b/.test(text)) {
    return {
      intent: "conversation.capability_summary",
      response: `${nexusWorkforceCapabilitySummary()} What do you need first?`,
      status: "completed",
      metadata: { ...metadataBase, redirectSection: "agent", suggestedReplies: ["start training", "show job pathways", "open health access", "open AgriTrade"] }
    };
  }
  if (has(clinicSignals)) {
    return {
      intent: "conversation.clinic_map_help",
      response: "I opened the clinic and pharmacy map. Share your village, city, or nearest landmark, and I will guide the closest clinic, mobile clinic, or pharmacy route. If this is urgent, call local emergency help now.",
      status: "needs-location",
      metadata: { ...guidedFrontier("Healthcare", "health", "What village, city, or landmark are you near?", "medium"), redirectSection: "map", suggestedReplies: ["use my location", "find clinic", "find pharmacy"] }
    };
  }
  if (has(doctorSignals)) {
    return {
      intent: "conversation.doctor_help",
      response: "I heard you need care support. I can guide you step by step. I cannot give medical decisions, but I can check danger signs, find clinic or mobile clinic support, and prepare a provider handoff. Where are you now?",
      status: "needs-details",
      metadata: { ...guidedFrontier("Healthcare", "health", "Where are you now?", "medium"), redirectSection: "health", suggestedReplies: ["start intake", "find clinic", "call provider"] }
    };
  }
  if (has(medicineSignals)) {
    return {
      intent: "conversation.medicine_help",
      response: "I heard you need medicine. I can guide you step by step. I cannot prescribe, but I can help find pharmacy or mobile clinic support and prepare provider review. What medicine concern and what village or city?",
      status: "needs-location",
      metadata: { ...guidedFrontier("Healthcare", "health", "What medicine concern and what village or city?", "medium"), redirectSection: "health", suggestedReplies: ["find pharmacy", "start intake", "call provider"] }
    };
  }
  if (has(cropProblemSignals) && !/\b(auto\s*pilot|autopilot)\b/.test(text)) {
    const cropUrgency = /\b(no rain|drought|dying|dead|very dry|unsafe|urgent|emergency)\b/.test(text) ? "high" : "normal";
    return {
      intent: "conversation.crop_help",
      response: "I can help with the crop problem. I can guide a field scan, simple next steps, buyer evidence, and route planning. What crop is it, and what do you see on the leaves, soil, or fruit?",
      status: "completed",
      metadata: { ...guidedFrontier("AgriTrade", "trade", "What crop is it, and what do you see on the leaves, soil, or fruit?", cropUrgency), redirectSection: "trade", suggestedReplies: ["run field scan", "explain crop problem", "contact buyer"] }
    };
  }
  if (has(cropSaleSignals) && !/\b(start to finish|end to end|safely|safe)\b/.test(text)) {
    return {
      intent: "conversation.crop_sale_help",
      response: "I can help sell the crop. I will help prepare buyer contact, sale evidence, and delivery tracking. What crop, quantity, farm location, and buyer should we use?",
      status: "needs-details",
      metadata: { ...guidedFrontier("AgriTrade", "trade", "What crop, quantity, farm location, and buyer should we use?"), redirectSection: "trade", suggestedReplies: ["maize in Kenya", "find a buyer", "track delivery"] }
    };
  }
  if (has(workSignals) && !/\bapply\b.*\b(that job|this job|the job)\b/.test(text)) {
    return {
      intent: "conversation.workforce_help",
      response: "I can help with work. I will show role options, skill gaps, training links, and the application step. What country and what kind of work do you want?",
      status: "completed",
      metadata: { ...guidedFrontier("Workforce", "workforce", "What country and what kind of work do you want?"), redirectSection: "workforce", suggestedReplies: ["show me jobs", "apply for a role", "review my skills"] }
    };
  }
  if (has(learningSignals) && !/\b(i am new|i'm new|how do i|where do i start|show me how|walk me through|guide me)\b/.test(text)) {
    return {
      intent: "conversation.learning_start",
      response: "I can help you learn by voice, captions, and slow lessons. I can start a recommended course and read it with support. What skill do you want to learn first?",
      status: "needs-topic",
      metadata: { ...guidedFrontier("Learning", "learning", "What skill do you want to learn first?"), redirectSection: "learning", suggestedReplies: ["start recommended course", "build captions", "read the lesson"] }
    };
  }
  if (/\b(use my location|use location|my location|gps)\b/.test(text)) {
    return {
      intent: "map.location_permission",
      response: "I can use your location after the browser gives permission. I opened map support so you can allow location and continue route, clinic, pharmacy, or shipment tracking.",
      status: "needs-permission",
      metadata: { ...guidedFrontier("Maps", "map", "Allow browser location when you are ready."), redirectSection: "map", suggestedReplies: ["allow location", "find clinic near me", "track shipment"] }
    };
  }
  if (has(mapSignals)) {
    return {
      intent: "conversation.map_open",
      response: "Full map is open. You can zoom, drag, find facilities, check routes, and track shipments. Where are you starting, and where do you need to go?",
      status: "completed",
      metadata: { ...guidedFrontier("Maps", "map", "Where are you starting, and where do you need to go?"), redirectSection: "map", suggestedReplies: ["find clinic near me", "track shipment", "show trade route"] }
    };
  }
  return null;
}

function urgentHealthSafetyResponse(db, user, text = "") {
  const lower = normalizeSpeechForIntent(text);
  const vulnerablePerson = /\b(baby|child|kid|infant|mother|father|grandma|grandmother|elder|person|patient|my child|my baby)\b/.test(lower);
  const babyOrChildHealth = /\b(baby|child|kid|infant|my child|my baby)\b/.test(lower) && /\b(sick|hot|fever|weak|pain|vomit|cough|hurt|help|no english|no doctor)\b/.test(lower);
  const dangerSign = /\b(cannot breathe|can't breathe|cant breathe|not breathing|no breathing|trouble breathing|hard breathing|bleeding|blood|seizure|convulsion|unconscious|not waking|very weak|weak|blue lips|chest pain|high fever|very hot|farm accident|accident)\b/.test(lower);
  const healthNeed = /\b(sick|hurt|pain|injury|doctor|clinic|medicine|health|help|fever|hot)\b/.test(lower);
  if (!(babyOrChildHealth || (dangerSign && (vulnerablePerson || healthNeed)))) return null;
  db.profile.agentMemory.activeModule = "Healthcare";
  db.profile.agentMemory.lastStatus = "urgent-health-safety";
  db.profile.agentMemory.lastSummary = `Urgent health safety guidance for: ${text}`;
  db.profile.agentMemory.updatedAt = new Date().toISOString();
  rememberAgentMemory(db.profile, `Urgent health concern reported: ${text}`, { source: "urgent-health-safety", category: "safety", module: "Healthcare", confidence: 0.97 });
  return {
    intent: "conversation.health_urgent_safety",
    response: "Call emergency services now if available, such as 911 in the U.S. If the person cannot breathe, is bleeding badly, not waking, or getting worse, seek emergency help now. I am not a doctor and AgriNexus cannot replace emergency services. After you call, tell me where you are and whether the person is breathing normally.",
    status: "urgent-guidance",
    metadata: {
      conversationMode: true,
      redirectSection: "health",
      suppressBehaviorNudge: true,
      frontierCommunication: {
        urgency: "high",
        nextQuestion: "After emergency help is called, where are you, and is the person breathing normally?",
        confidence: 0.97
      },
      suggestedReplies: ["find clinic", "call provider", "start intake"]
    }
  };
}

function healthAccessVoiceAcceptanceResponse(db, user, text = "", lower = "", options = {}) {
  if (options.conversational !== true) return null;
  const value = normalizeSpeechForIntent(text);
  const metadataBase = { conversationMode: true, suppressBehaviorNudge: true, healthAccessVoice: true };
  const response = (intent, status, redirectSection, message, suggestedReplies = ["start intake", "find clinic", "call provider"], extraMetadata = {}) => {
    if (/^needs-/.test(String(status || ""))) {
      setSimpleVoiceTurn(db, {
        domain: intent.includes("medicine") ? "medicine" : intent.includes("clinic") ? "clinic" : "doctor",
        section: redirectSection,
        question: message,
        choices: suggestedReplies,
        defaultChoice: suggestedReplies[0] || "clinic",
        sourceIntent: intent
      });
    }
    return {
      intent,
      response: message,
      status,
      metadata: {
        ...metadataBase,
        redirectSection,
        moduleSignal: extraMetadata.moduleSignal || { module: "Healthcare", section: "health" },
        frontierCommunication: extraMetadata.frontierCommunication || {
          urgency: /urgent|emergency|bleeding|cannot breathe|very hot|weak/.test(value) ? "high" : "medium",
          nextQuestion: message.includes("?")
            ? message.slice(Math.max(0, message.lastIndexOf(".") + 1)).trim()
            : "Where are you, and what health support do you need first?",
          confidence: 0.95,
          responseShape: "acknowledge health need, route to care support, guide one safe next step"
        },
        suggestedReplies,
        ...extraMetadata
      }
    };
  };

  if (/\b(caption|captions|transcript|subtitles?)\b.*\b(telehealth|health|patient|doctor|provider|clinic|care)\b|\b(telehealth|health|patient|doctor|provider|clinic|care)\b.*\b(caption|captions|transcript|subtitles?)\b/.test(value)) {
    return response(
      "conversation.telehealth_captions",
      "completed",
      "health",
      "I can build captions for telehealth. I will prepare a caption relay so the patient, caregiver, and provider can read clearly. Who needs captions first?",
      ["start caption relay", "start intake", "call provider"]
    );
  }

  if (/\b(healthcare|health care|medical|clinic|telehealth)\b.*\b(partner|provider|practitioner|ngo|government)\b|\b(partner|provider|practitioner|ngo|government)\b.*\b(healthcare|health care|medical|clinic|telehealth)\b/.test(value)) {
    return response(
      "conversation.healthcare_partner_explain",
      "completed",
      "health",
      "For a healthcare partner, AgriNexus supports non-diagnostic intake, mobile clinic coordination, clinic and pharmacy location help, captions, provider handoff packets, and follow-up evidence.",
      ["start intake", "show mobile clinic support", "show pharmacy on the map"]
    );
  }

  if (/\b(mobile clinic|field clinic|outreach clinic|clinic outreach|rural clinic)\b/.test(value)) {
    return response(
      "conversation.mobile_clinic_help",
      "completed",
      "health",
      "Mobile clinics bring basic care access closer to a community through outreach teams or local care points. AgriNexus can help prepare intake details, find clinic or pharmacy support, and create a safe handoff packet, but this local demo does not dispatch or book a live mobile clinic by itself.",
      ["start health intake", "find a clinic near me", "show pharmacy on the map"]
    );
  }

  const healthAccessReadingNeed = /\b(no english|cannot read|can't read|cant read|i cannot read|i cant read|illiterate|read for me|help me read)\b/.test(value)
    && /\b(health|doctor|clinic|medicine|pharmacy|patient|telehealth|care|sick|baby|child|mother|grandma|provider|intake)\b/.test(value)
    && !/\b(teach|lesson|course|learn|learning|school|training)\b/.test(value);
  if (healthAccessReadingNeed
    || /\b(baby sick|child sick|sick baby)\b/.test(value)
    || /\b(start|open|begin)\b.*\b(health )?(intake|telehealth intake|patient intake)\b/.test(value)
    || /\b(health )?(intake|telehealth intake|patient intake)\b.*\b(start|open|begin|help)\b/.test(value)
    || /^start intake$/.test(value)) {
    if (/\b(ask me questions|ask questions|question|questions|one question)\b/.test(value)) {
      return startConversationalIntake(db, text, "health");
    }
    return response(
      "conversation.health_intake",
      "needs-details",
      "health",
      "I started health intake. I cannot make medical decisions, but I will ask one simple question at a time and prepare the safest support step. Who needs care, and where are they?",
      ["patient name", "find clinic", "I need medicine"]
    );
  }

  const requestedHealthLocation = knownMapLocation(value);
  if (/\b(kenya|nairobi|kibera|mukuru|mathare|kawangware|kangemi|kiambu|thika|ruiru)\b/.test(value)
    && /\b(medical transport|health transport|clinic route|mobile clinic|township|townships|village|villages|pharmacy|medical supply|care route)\b/.test(value)) {
    return response(
      "map.kenya_medical_transport",
      "completed",
      "map",
      "I opened Kenya medical transport mapping. The map can show Nairobi township and village access points including Kibera, Mukuru, Mathare, Kawangware, Kangemi, Kiambu, Ruiru, and Thika, with clinic, pharmacy, mobile clinic, and medical supply corridors. What area should I focus on?",
      ["find clinic near Kibera", "show pharmacy near Mukuru", "track mobile clinic route"],
      { countryId: "kenya", countryName: "Kenya", lat: 0.0236, lng: 37.9062, mapLayer: "kenya-medical-transport" }
    );
  }
  if (requestedHealthLocation
    && /\b(clinic|hospital|health center|health centre|pharmacy|medicine|mobile clinic|medical transport|medical supply)\b/.test(value)
    && /\b(map|show|find|near|nearest|nearby|closest|where|location|route|transport)\b/.test(value)) {
    return response(
      "map.kenya_medical_transport",
      "completed",
      "map",
      `I opened health transport mapping for ${requestedHealthLocation.label}. Nexus can show nearby clinic, pharmacy, mobile clinic, and medical supply access points, then help prepare intake or transport handoff. What support point should I show first?`,
      ["start intake", "show pharmacy on the map", "track mobile clinic route"],
      { countryId: "kenya", countryName: "Kenya", lat: 0.0236, lng: 37.9062, mapLayer: "kenya-medical-transport", requestedLocation: requestedHealthLocation }
    );
  }

  if (/\b(pharmacy|medicine|medication|refill|drug|pills)\b/.test(value) && /\b(map|show|find|near|nearest|where|location)\b/.test(value)) {
    return response(
      "conversation.clinic_map_help",
      "needs-location",
      "map",
      "I heard you need clinic or pharmacy support on the map. I can show nearby clinic, mobile clinic, or pharmacy options and help prepare a safe handoff. First, tell me what village, city, or landmark you are near.",
      ["use my location", "find clinic", "find pharmacy"]
    );
  }

  if (/\b(clinic|hospital|health center|health centre)\b/.test(value) && /\b(map|near|nearest|nearby|closest|where|location|find|show)\b/.test(value)) {
    return response(
      "conversation.clinic_map_help",
      "needs-location",
      "map",
      "I heard you need clinic or pharmacy support on the map. I can show nearby clinic, mobile clinic, or pharmacy options and help prepare a safe handoff. First, tell me what village, city, or landmark you are near.",
      ["use my location", "find clinic", "find pharmacy"]
    );
  }

  if (/\b(call|contact|speak to|talk to|connect to|reach|get)\b.*\b(provider|doctor|nurse|clinician)\b|\b(i need|need|want|see|find|help)\b.*\b(doctor|provider|nurse|clinician)\b/.test(value)) {
    return response(
      "conversation.doctor_help",
      "needs-details",
      "health",
      "I heard you need a doctor. I can guide you step by step. I cannot give medical decisions, but I can check danger signs, find clinic or mobile clinic support, and prepare a provider handoff. Where are you now?",
      ["start intake", "find clinic", "call provider"]
    );
  }

  if (/\b(medicine|medication|pharmacy|refill|drug|pills|prescription|dawa|remedy)\b/.test(value)) {
    return response(
      "conversation.medicine_help",
      "needs-location",
      "health",
      "I heard you need medicine. I can guide you step by step. I cannot prescribe, but I can find pharmacy or mobile clinic support and prepare provider review. What medicine concern and what village or city?",
      ["find pharmacy", "start intake", "call provider"]
    );
  }

  return null;
}

