function nexusEnvValue(env, name, aliases = []) {
  const candidates = [name, ...aliases];
  for (const candidate of candidates) {
    const value = String(env[candidate] || "").trim();
    if (value) return { name: candidate, present: true };
  }
  return { name, present: false };
}

function nexusFlagEnabled(env, name) {
  return String(env[name] || "").trim().toLowerCase() === "true";
}

function ensureNexusProductionRailsState(db) {
  ensureNexusPilotState(db);
  if (!Array.isArray(db.nexusIntegrationAttempts)) db.nexusIntegrationAttempts = [];
  if (!Array.isArray(db.nexusExportDeleteRequests)) db.nexusExportDeleteRequests = [];
  if (!Array.isArray(db.nexusProductionReadinessEvents)) db.nexusProductionReadinessEvents = [];
  if (!Array.isArray(db.nexusKnowledgeQueries)) db.nexusKnowledgeQueries = [];
  if (!Array.isArray(db.nexusKnowledgeSavedResults)) db.nexusKnowledgeSavedResults = [];
  if (!Array.isArray(db.nexusKnowledgeReviewSummaries)) db.nexusKnowledgeReviewSummaries = [];
  if (!Array.isArray(db.nexusProviderPathwayRequests)) db.nexusProviderPathwayRequests = [];
  if (!Array.isArray(db.nexusProviderOrganizations)) db.nexusProviderOrganizations = [];
  if (!Array.isArray(db.nexusProviderReviewers)) db.nexusProviderReviewers = [];
  if (!Array.isArray(db.nexusRoutingRules)) db.nexusRoutingRules = [];
  if (!Array.isArray(db.nexusRoutingLogs)) db.nexusRoutingLogs = [];
  if (!Array.isArray(db.nexusProviderResponses)) db.nexusProviderResponses = [];
  if (!Array.isArray(db.nexusCases)) db.nexusCases = [];
  if (!Array.isArray(db.nexusCaseTimeline)) db.nexusCaseTimeline = [];
  if (!Array.isArray(db.nexusCommunications)) db.nexusCommunications = [];
  if (!Array.isArray(db.nexusNotifications)) db.nexusNotifications = [];
  if (!Array.isArray(db.nexusOutcomes)) db.nexusOutcomes = [];
  if (!Array.isArray(db.nexusTelehealthEncounters)) db.nexusTelehealthEncounters = [];
  if (!Array.isArray(db.nexusTelehealthFollowUps)) db.nexusTelehealthFollowUps = [];
  if (!Array.isArray(db.nexusTelehealthVideoAttempts)) db.nexusTelehealthVideoAttempts = [];
  if (!Array.isArray(db.nexusLaunchBlockers)) db.nexusLaunchBlockers = [];
  if (!Array.isArray(db.nexusLegalSafetyPages)) db.nexusLegalSafetyPages = [];
  if (!Array.isArray(db.nexusAttachmentReadinessEvents)) db.nexusAttachmentReadinessEvents = [];
  if (!Array.isArray(db.nexusMarketplaceExecutionAttempts)) db.nexusMarketplaceExecutionAttempts = [];
  if (!Array.isArray(db.nexusHighRiskBlockedAttempts)) db.nexusHighRiskBlockedAttempts = [];
  if (!Array.isArray(db.nexusAiAnswerReports)) db.nexusAiAnswerReports = [];
  ensureNexusEndgameSeeds(db);
  const profile = db.nexusPilotProfiles[0];
  if (profile) {
    profile.accountId = profile.accountId || "standard-user-local";
    profile.authMode = profile.authMode || "local prototype account";
    profile.role = NEXUS_PRODUCTION_ROLES.includes(profile.role) ? profile.role : "Standard User";
    profile.productionRailReady = true;
    profile.preferredLanguage = profile.preferredLanguage || "English";
    profile.languageCode = profile.languageCode || "en";
  }
}

function nexusProductionStorageStatus(db, env = process.env) {
  ensureNexusProductionRailsState(db);
  const requestedMode = String(env.NEXUS_STORAGE_MODE || "local_json").trim();
  const mode = NEXUS_PRODUCTION_STORAGE_MODES.includes(requestedMode) ? requestedMode : "local_json";
  return {
    ok: true,
    mode,
    configured: mode === "local_json" || mode === "memory" || Boolean(env.NEXUS_EXTERNAL_DATABASE_URL),
    externalDatabaseConfigured: Boolean(env.NEXUS_EXTERNAL_DATABASE_URL),
    adapter: "nexusProductionStorageAdapter",
    lifecycle: {
      create: true,
      update: true,
      archive: true,
      exportRequest: true,
      deleteRequest: true,
      hardDelete: false
    },
    collections: {
      profiles: db.nexusPilotProfiles.length,
      records: db.nexusPilotRecords.length,
      reviewQueue: db.nexusPilotReviewQueue.length,
      consentEvents: db.nexusPilotConsentEvents.length,
      auditEvents: db.nexusPilotAuditEvents.length,
      reminders: db.nexusPilotReminders.length,
      offlineQueue: db.nexusPilotOfflineQueue.length,
      integrationAttempts: db.nexusIntegrationAttempts.length,
      exportDeleteRequests: db.nexusExportDeleteRequests.length
    },
    safety: "Local JSON storage is active for this prototype. External database production deployment requires explicit configuration and migration review."
  };
}

function nexusProductionIntegrationStatus(db, env = process.env) {
  ensureNexusProductionRailsState(db);
  return NEXUS_PRODUCTION_INTEGRATIONS.map(integration => {
    const enabled = nexusFlagEnabled(env, integration.enabledFlag);
    const missing = [];
    const configuredEnv = [];
    for (const envName of integration.requiredEnv) {
      const found = nexusEnvValue(env, envName, integration.optionalEnvAliases?.[envName] || []);
      if (found.present) configuredEnv.push(found.name);
      else missing.push(envName);
    }
    if (Array.isArray(integration.oneOfEnv) && integration.oneOfEnv.length) {
      const oneOfConfigured = integration.oneOfEnv.some(envName => {
        if (envName === "OPENAI_API_KEY") {
          return nexusFlagEnabled(env, "OPENAI_WEB_SEARCH_ENABLED") && nexusEnvValue(env, "OPENAI_API_KEY").present;
        }
        const found = nexusEnvValue(env, envName);
        if (found.present) configuredEnv.push(found.name);
        return found.present;
      });
      if (!oneOfConfigured) missing.push(integration.oneOfEnv.join(" or "));
    }
    const configured = missing.length === 0;
    return {
      id: integration.id,
      name: integration.name,
      type: integration.type,
      enabledFlag: integration.enabledFlag,
      enabled,
      configured,
      missingEnv: missing,
      configuredEnvNamesOnly: configuredEnv,
      testability: !enabled ? "disabled" : configured ? "sandbox_ready" : "missing_config",
      actionRiskTier: integration.riskTier,
      whatCanBeTestedNow: !enabled
        ? "Readiness display and missing configuration guidance only."
        : configured
          ? "Provider-specific sandbox or read-only test path after explicit confirmation."
          : "Configuration readiness only; execution remains blocked.",
      whatStillNeeded: configured
        ? "Explicit user approval, audit event, provider response validation, and production approval before live use."
        : `Add missing environment variable names: ${missing.join(", ") || "none"}.`,
      executionEnabled: false,
      userApprovalRequired: true,
      auditRequired: true,
      noSilentExecution: true,
      noSecretValuesReturned: true,
      capability: integration.capability
    };
  });
}

function nexusKnowledgeSourceList() {
  const categories = Object.entries(NEXUS_KNOWLEDGE_TRUSTED_SOURCES).map(([id, item]) => ({
    id,
    label: item.label,
    preferredSources: item.preferredSources,
    safetyNote: item.safetyNote,
    recordType: item.recordType,
    fallbackWhenUnavailable: "Use honest built-in guidance, zero citations, local save/offline queue, and review-summary preparation.",
    providerAdvisorSupportOffered: !["music_media", "reminders", "offline", "general"].includes(id),
    consentRequiredForReview: ["health", "chronicCare", "telehealth", "pharmacy", "mobileClinic"].includes(id)
  }));
  return [
    ...categories,
    {
      id: "health_chronic_care",
      label: "Health/chronic care education",
      preferredSources: NEXUS_KNOWLEDGE_TRUSTED_SOURCES.chronicCare.preferredSources,
      safetyNote: NEXUS_KNOWLEDGE_TRUSTED_SOURCES.chronicCare.safetyNote,
      recordType: NEXUS_KNOWLEDGE_TRUSTED_SOURCES.chronicCare.recordType,
      aliasFor: "chronicCare",
      fallbackWhenUnavailable: "Use honest built-in guidance, zero citations, local save/offline queue, and review-summary preparation.",
      providerAdvisorSupportOffered: true,
      consentRequiredForReview: true
    }
  ];
}

const NEXUS_LIVE_KNOWLEDGE_PROVIDER_PRIORITY = Object.freeze(["tavily", "brave", "exa", "generic"]);
const NEXUS_LIVE_KNOWLEDGE_ALLOWED_PROVIDERS = Object.freeze(["auto", "tavily", "brave", "exa", "generic"]);
let nexusLiveKnowledgeLastTestResult = null;
const NEXUS_LIVE_KNOWLEDGE_SHARED_DOMAINS = Object.freeze([
  "agriculture", "crop", "farm", "field", "logistics", "route",
  "training", "workforce", "employer",
  "chronic", "diabetes", "hypertension", "obesity", "RPM", "RTM", "CHW",
  "telehealth", "pharmacy", "mobile clinic", "marketplace",
  "communications", "email", "SMS", "WhatsApp", "phone", "Telegram"
]);

function nexusLiveKnowledgeProviderPreference(env = process.env) {
  const raw = String(env.NEXUS_LIVE_KNOWLEDGE_PROVIDER || env.WEB_SEARCH_PROVIDER || "auto").trim().toLowerCase();
  return raw || "auto";
}

function nexusLiveKnowledgeDomainForInput(domain = "", mode = "", query = "") {
  const raw = String(domain || mode || "").trim();
  const text = `${raw} ${query || ""}`.toLowerCase();
  if (/\b(diabetes|glucose|blood sugar)\b/.test(text)) return "diabetes";
  if (/\b(hypertension|blood pressure|bp)\b/.test(text)) return "hypertension";
  if (/\b(obesity|weight)\b/.test(text)) return "obesity";
  if (/\b(rpm|remote patient monitoring)\b/.test(text)) return "RPM";
  if (/\b(rtm|remote therapeutic monitoring)\b/.test(text)) return "RTM";
  if (/\b(chw|community health worker)\b/.test(text)) return "CHW";
  if (/\b(chronic|health|clinic|medical|patient)\b/.test(text)) return "chronic";
  if (/\b(telehealth|video visit|provider bridge|provider questions)\b/.test(text)) return "telehealth";
  if (/\b(pharmacy|medication|medicine|prescription|refill)\b/.test(text)) return "pharmacy";
  if (/\b(mobile clinic|clinic van|outreach)\b/.test(text)) return "mobile clinic";
  if (/\b(whatsapp)\b/.test(text)) return "WhatsApp";
  if (/\b(sms|text message)\b/.test(text)) return "SMS";
  if (/\b(email)\b/.test(text)) return "email";
  if (/\b(phone|call)\b/.test(text)) return "phone";
  if (/\b(telegram)\b/.test(text)) return "Telegram";
  if (/\b(message|communications|communication)\b/.test(text)) return "communications";
  if (/\b(marketplace|vendor|buyer|seller|agritrade)\b/.test(text)) return "marketplace";
  if (/\b(logistics|delivery|rural delivery)\b/.test(text)) return "logistics";
  if (/\b(route|map|field visit|directions)\b/.test(text)) return "route";
  if (/\b(field|farm visit)\b/.test(text)) return "field";
  if (/\b(employer)\b/.test(text)) return "employer";
  if (/\b(workforce|jobs|career)\b/.test(text)) return "workforce";
  if (/\b(training|learning|literacy|course)\b/.test(text)) return "training";
  if (/\b(crop|cassava|maize|pest|disease|yellow leaves)\b/.test(text)) return "crop";
  if (/\b(farm|irrigation|soil)\b/.test(text)) return "farm";
  if (/\b(agriculture|agronomy)\b/.test(text)) return "agriculture";
  return raw || "general";
}

function nexusLiveKnowledgeCategoryForDomain(domain = "general") {
  const normalized = String(domain || "general").trim();
  if (["diabetes", "hypertension", "obesity", "RPM", "RTM", "CHW", "chronic"].includes(normalized)) return "chronicCare";
  if (normalized === "telehealth") return "telehealth";
  if (normalized === "pharmacy") return "pharmacy";
  if (normalized === "mobile clinic") return "mobileClinic";
  if (["crop", "farm", "field", "agriculture"].includes(normalized)) return "agriculture";
  if (["logistics", "route"].includes(normalized)) return "maps";
  if (["training"].includes(normalized)) return "learning";
  if (["workforce", "employer"].includes(normalized)) return "jobs";
  if (normalized === "marketplace") return "marketplace";
  if (["communications", "email", "SMS", "WhatsApp", "phone", "Telegram"].includes(normalized)) return "general";
  return "general";
}

function nexusLiveKnowledgeProviderCatalog(env = process.env) {
  return [
    { provider: "tavily", requiredEnvVars: ["TAVILY_API_KEY"], fallbackEnvVars: ["NEXUS_LIVE_KNOWLEDGE_API_KEY"], endpointEnvVars: [], citationCapability: true, configured: Boolean(String(env.TAVILY_API_KEY || "").trim()) || nexusLiveKnowledgeGenericApiKeyApplies("tavily", env) },
    { provider: "brave", requiredEnvVars: ["BRAVE_SEARCH_API_KEY"], fallbackEnvVars: ["NEXUS_LIVE_KNOWLEDGE_API_KEY"], endpointEnvVars: [], citationCapability: true, configured: Boolean(String(env.BRAVE_SEARCH_API_KEY || "").trim()) || nexusLiveKnowledgeGenericApiKeyApplies("brave", env) },
    { provider: "exa", requiredEnvVars: ["EXA_API_KEY"], fallbackEnvVars: ["NEXUS_LIVE_KNOWLEDGE_API_KEY"], endpointEnvVars: [], citationCapability: true, configured: Boolean(String(env.EXA_API_KEY || "").trim()) || nexusLiveKnowledgeGenericApiKeyApplies("exa", env) },
    { provider: "generic", requiredEnvVars: ["NEXUS_LIVE_KNOWLEDGE_API_KEY", "NEXUS_LIVE_KNOWLEDGE_PROVIDER_ENDPOINT"], fallbackEnvVars: [], citationCapability: true, configured: Boolean(String(env.NEXUS_LIVE_KNOWLEDGE_API_KEY || "").trim() && String(env.NEXUS_LIVE_KNOWLEDGE_PROVIDER_ENDPOINT || "").trim()) }
  ].map(item => ({
    ...item,
    missingEnvVars: item.configured ? [] : item.requiredEnvVars.filter(envName => !String(env[envName] || "").trim()),
    secretValuesReturned: false
  }));
}

function nexusLiveKnowledgeGenericApiKeyApplies(provider, env = process.env) {
  const selectedProvider = nexusLiveKnowledgeProviderPreference(env);
  const genericKey = String(env.NEXUS_LIVE_KNOWLEDGE_API_KEY || "").trim();
  return Boolean(genericKey && selectedProvider === provider && ["tavily", "brave", "exa"].includes(provider));
}

function nexusLiveKnowledgeApiKeyForProvider(provider, env = process.env) {
  const primaryEnvByProvider = {
    tavily: "TAVILY_API_KEY",
    brave: "BRAVE_SEARCH_API_KEY",
    exa: "EXA_API_KEY"
  };
  const primaryEnv = primaryEnvByProvider[provider];
  const primaryValue = primaryEnv ? String(env[primaryEnv] || "").trim() : "";
  if (primaryValue) return primaryValue;
  return nexusLiveKnowledgeGenericApiKeyApplies(provider, env)
    ? String(env.NEXUS_LIVE_KNOWLEDGE_API_KEY || "").trim()
    : "";
}

function nexusKnowledgeProviderErrorMessage(payload = {}, fallback = "Provider request failed") {
  const candidates = [
    payload?.error?.message,
    payload?.error?.detail,
    payload?.error,
    payload?.message,
    payload?.detail,
    fallback
  ];
  const candidate = candidates.find(value => value !== undefined && value !== null && String(value).trim());
  const raw = typeof candidate === "object"
    ? JSON.stringify(candidate)
    : String(candidate || fallback);
  return sanitizePilotText(raw, 220) || fallback;
}

function nexusKnowledgeProviderStatus(env = process.env) {
  const providerPreference = nexusLiveKnowledgeProviderPreference(env);
  const allModeProviders = nexusLiveKnowledgeProviderCatalog(env);
  const selectedProviderPreference = NEXUS_LIVE_KNOWLEDGE_ALLOWED_PROVIDERS.includes(providerPreference) ? providerPreference : "unsupported";
  const providerPriority = NEXUS_LIVE_KNOWLEDGE_PROVIDER_PRIORITY;
  const selectedAllModeProvider = selectedProviderPreference === "auto"
    ? allModeProviders.find(item => providerPriority.includes(item.provider) && item.configured)
    : allModeProviders.find(item => item.provider === selectedProviderPreference && item.configured);
  const openAiReady = nexusFlagEnabled(env, "OPENAI_WEB_SEARCH_ENABLED") && Boolean(String(env.OPENAI_API_KEY || "").trim());
  const providerEndpointReady = Boolean(String(env.NEXUS_LIVE_KNOWLEDGE_PROVIDER_ENDPOINT || "").trim());
  const supportedProviders = [
    { provider: "tavily", requiredEnv: ["TAVILY_API_KEY"], fallbackEnv: ["NEXUS_LIVE_KNOWLEDGE_API_KEY"], citationCapable: true },
    { provider: "brave", requiredEnv: ["BRAVE_SEARCH_API_KEY"], fallbackEnv: ["NEXUS_LIVE_KNOWLEDGE_API_KEY"], citationCapable: true },
    { provider: "exa", requiredEnv: ["EXA_API_KEY"], fallbackEnv: ["NEXUS_LIVE_KNOWLEDGE_API_KEY"], citationCapable: true },
    { provider: "generic", requiredEnv: ["NEXUS_LIVE_KNOWLEDGE_API_KEY", "NEXUS_LIVE_KNOWLEDGE_PROVIDER_ENDPOINT"], citationCapable: true },
    { provider: "openai-web-search", requiredEnv: ["OPENAI_WEB_SEARCH_ENABLED", "OPENAI_API_KEY"], citationCapable: true },
    { provider: "provider-endpoint", requiredEnv: ["NEXUS_LIVE_KNOWLEDGE_PROVIDER_ENDPOINT"], citationCapable: true }
  ];
  const providerMissingEnv = item => item.requiredEnv.filter(envName => {
    if (envName === "OPENAI_WEB_SEARCH_ENABLED") return !nexusFlagEnabled(env, envName);
    if (["TAVILY_API_KEY", "BRAVE_SEARCH_API_KEY", "EXA_API_KEY"].includes(envName)) {
      return !String(env[envName] || "").trim() && !nexusLiveKnowledgeGenericApiKeyApplies(item.provider, env);
    }
    return !String(env[envName] || "").trim();
  });
  const isProviderConfigured = item => item.provider === "openai-web-search"
    ? openAiReady
    : item.provider === "provider-endpoint"
      ? providerEndpointReady
      : providerMissingEnv(item).length === 0;
  const selectedByPreference = supportedProviders.find(item => item.provider === providerPreference);
  const unsupportedProvider = Boolean(providerPreference && !["auto", ...supportedProviders.map(item => item.provider)].includes(providerPreference));
  const selected = unsupportedProvider
    ? null
    : selectedAllModeProvider
    ? supportedProviders.find(item => item.provider === selectedAllModeProvider.provider)
    : selectedByPreference && isProviderConfigured(selectedByPreference)
    ? selectedByPreference
    : supportedProviders.find(isProviderConfigured);
  const enabled = nexusFlagEnabled(env, "NEXUS_LIVE_KNOWLEDGE_ENABLED");
  const configured = Boolean(selected);
  const preferredMissing = unsupportedProvider
    ? ["NEXUS_LIVE_KNOWLEDGE_PROVIDER"]
    : selectedByPreference && !configured
    ? providerMissingEnv(selectedByPreference)
    : [];
  const missingEnv = configured
    ? []
    : preferredMissing.length
      ? preferredMissing
      : ["TAVILY_API_KEY", "BRAVE_SEARCH_API_KEY", "EXA_API_KEY", "NEXUS_LIVE_KNOWLEDGE_API_KEY with exact provider", "OPENAI_WEB_SEARCH_ENABLED + OPENAI_API_KEY", "NEXUS_LIVE_KNOWLEDGE_PROVIDER_ENDPOINT"];
  const allModeMissing = configured
    ? []
    : selectedProviderPreference === "unsupported"
      ? ["NEXUS_LIVE_KNOWLEDGE_PROVIDER"]
      : selectedProviderPreference === "auto"
        ? ["TAVILY_API_KEY", "BRAVE_SEARCH_API_KEY", "EXA_API_KEY", "NEXUS_LIVE_KNOWLEDGE_API_KEY", "NEXUS_LIVE_KNOWLEDGE_PROVIDER_ENDPOINT"]
        : (allModeProviders.find(item => item.provider === selectedProviderPreference)?.missingEnvVars || []);
  return {
    ok: true,
    enabled,
    configured,
    selectedProvider: providerPreference || "auto",
    provider: configured ? selected.provider : "not-configured",
    providerEnvName: configured ? selected.requiredEnv.join(" + ") : "",
    testability: !enabled ? "disabled" : unsupportedProvider ? "blocked" : configured ? "ready" : "missing_config",
    missingEnv,
    supportedProviders,
    unsupportedProvider,
    providerState: !enabled ? "disabled" : unsupportedProvider ? "unsupported_provider" : configured ? "configured" : "missing_config",
    providerSelectionMessage: unsupportedProvider
      ? "NEXUS_LIVE_KNOWLEDGE_PROVIDER must be one of: auto, tavily, brave, exa, generic."
      : "",
    providerPriority,
    liveKnowledgeProviderPriority: providerPriority,
    supportedLiveKnowledgeProviders: allModeProviders,
    requiredEnvVars: selectedProviderPreference === "auto"
      ? ["TAVILY_API_KEY", "BRAVE_SEARCH_API_KEY", "EXA_API_KEY", "NEXUS_LIVE_KNOWLEDGE_API_KEY", "NEXUS_LIVE_KNOWLEDGE_PROVIDER_ENDPOINT"]
      : (allModeProviders.find(item => item.provider === selectedProviderPreference)?.requiredEnvVars || []),
    missingEnvVars: allModeMissing,
    citationCapability: configured,
    citationCapable: configured,
    testabilityStatus: !enabled ? "disabled" : unsupportedProvider ? "blocked" : configured ? "ready" : "credential-blocked",
    safeDomains: NEXUS_LIVE_KNOWLEDGE_SHARED_DOMAINS,
    safeDomainsSupported: NEXUS_LIVE_KNOWLEDGE_SHARED_DOMAINS,
    timestamp: new Date().toISOString(),
    lastTestResult: nexusLiveKnowledgeLastTestResult,
    maxResults: Number(env.NEXUS_LIVE_KNOWLEDGE_MAX_RESULTS || 5),
    timeoutMs: Number(env.NEXUS_LIVE_KNOWLEDGE_TIMEOUT_MS || 9000),
    safeMode: String(env.NEXUS_LIVE_KNOWLEDGE_SAFE_MODE || "true").toLowerCase() !== "false",
    categories: nexusKnowledgeSourceList().map(item => item.id),
    citationHandlingReady: true,
    saveAttachReady: true,
    auditReady: true,
    disabledMessage: NEXUS_KNOWLEDGE_DISABLED_MESSAGE,
    noFakeCitations: true,
    noExecutionAuthorized: true,
    noLocationPermissionRequested: true,
    noDispatchAuthorized: true,
    noSecretValuesReturned: true
  };
}

const NEXUS_PRODUCTION_PROVIDER_EMAIL_ENVS = [
  "NEXUS_PROVIDER_REVIEW_EMAIL",
  "NEXUS_PHARMACY_REFERRAL_EMAIL",
  "NEXUS_MOBILE_CLINIC_REFERRAL_EMAIL",
  "NEXUS_AGRONOMY_REVIEW_EMAIL",
  "NEXUS_MARKETPLACE_VENDOR_EMAIL",
  "NEXUS_LOGISTICS_PARTNER_EMAIL",
  "NEXUS_TRAINING_PARTNER_EMAIL",
  "NEXUS_ADMIN_ALERT_EMAIL"
];

const NEXUS_PRODUCTION_PROVIDER_DESTINATION_ENVS = [
  "NEXUS_PROVIDER_REVIEW_SMS_TO",
  "NEXUS_PROVIDER_REVIEW_WHATSAPP_TO",
  "NEXUS_PHARMACY_SMS_TO",
  "NEXUS_PHARMACY_WHATSAPP_TO",
  "NEXUS_MOBILE_CLINIC_SMS_TO",
  "NEXUS_MOBILE_CLINIC_WHATSAPP_TO",
  "NEXUS_AGRONOMY_SMS_TO",
  "NEXUS_AGRONOMY_WHATSAPP_TO",
  "NEXUS_MARKETPLACE_VENDOR_SMS_TO",
  "NEXUS_MARKETPLACE_VENDOR_WHATSAPP_TO",
  "NEXUS_LOGISTICS_SMS_TO",
  "NEXUS_LOGISTICS_WHATSAPP_TO",
  "NEXUS_TRAINING_PARTNER_SMS_TO",
  "NEXUS_TRAINING_PARTNER_WHATSAPP_TO"
];

function nexusProductionConfiguredEnv(env = process.env, names = []) {
  return names.filter(name => String(env[name] || "").trim()).map(name => ({ name, configured: true }));
}

function nexusProductionMissingEnv(env = process.env, names = []) {
  return names.filter(name => !String(env[name] || "").trim());
}

function nexusProductionPublicStatus(env = process.env) {
  const liveKnowledge = nexusKnowledgeProviderStatus(env);
  const email = nexusEmailProviderStatus(env);
  const communications = nexusCommunicationsProviderStatus(env);
  const telehealth = nexusTelehealthProvider.status(env);
  const pharmacy = nexusProviderCoordinationStatus("pharmacy", env);
  const mobileClinic = nexusProviderCoordinationStatus("mobile-clinic", env);
  const dailyMissing = nexusProductionMissingEnv(env, ["DAILY_API_KEY", "DAILY_ROOM_DOMAIN"]);
  const providerEmailMissing = nexusProductionMissingEnv(env, NEXUS_PRODUCTION_PROVIDER_EMAIL_ENVS);
  const providerDestinationMissing = nexusProductionMissingEnv(env, NEXUS_PRODUCTION_PROVIDER_DESTINATION_ENVS);
  const publicAppUrlConfigured = Boolean(String(env.NEXUS_PUBLIC_APP_URL || env.RENDER_EXTERNAL_URL || "").trim());
  const missingEnv = Array.from(new Set([
    ...(publicAppUrlConfigured ? [] : ["NEXUS_PUBLIC_APP_URL"]),
    ...(liveKnowledge.configured ? [] : (liveKnowledge.missingEnvVars || liveKnowledge.missingEnv || [])),
    ...(email.configured ? [] : (email.missingEnv || [])),
    ...(communications.channels?.sms?.configured ? [] : (communications.channels?.sms?.missingEnv || [])),
    ...(communications.channels?.whatsapp?.configured ? [] : (communications.channels?.whatsapp?.missingEnv || [])),
    ...(telehealth.configured ? [] : (telehealth.missingEnv || [])),
    ...dailyMissing,
    ...providerEmailMissing,
    ...providerDestinationMissing,
    ...(pharmacy.configured ? [] : (pharmacy.missingEnv || [])),
    ...(mobileClinic.configured ? [] : (mobileClinic.missingEnv || []))
  ])).filter(name => !/secret|token value|password value/i.test(name));
  return {
    ok: true,
    app: "Nexus / AgriNexus",
    environment: env.NODE_ENV || "development",
    timestamp: new Date().toISOString(),
    publicAppUrlConfigured,
    liveKnowledgeConfigured: Boolean(liveKnowledge.enabled && liveKnowledge.configured),
    emailConfigured: Boolean(email.configured),
    smsConfigured: Boolean(communications.channels?.sms?.configured),
    whatsappConfigured: Boolean(communications.channels?.whatsapp?.configured),
    telehealthProviderConfigured: Boolean(telehealth.configured),
    dailyVideoConfigured: dailyMissing.length === 0,
    providerRecipientEmailsConfigured: providerEmailMissing.length < NEXUS_PRODUCTION_PROVIDER_EMAIL_ENVS.length,
    providerSmsWhatsappDestinationsConfigured: providerDestinationMissing.length < NEXUS_PRODUCTION_PROVIDER_DESTINATION_ENVS.length,
    providerLanes: {
      liveKnowledge: {
        provider: liveKnowledge.provider,
        selectedProvider: liveKnowledge.selectedProvider,
        configured: Boolean(liveKnowledge.enabled && liveKnowledge.configured),
        missingEnv: liveKnowledge.configured ? [] : (liveKnowledge.missingEnvVars || liveKnowledge.missingEnv || [])
      },
      email: {
        provider: email.provider,
        configured: Boolean(email.configured),
        missingEnv: email.missingEnv || []
      },
      communications: {
        provider: communications.provider,
        sms: {
          configured: Boolean(communications.channels?.sms?.configured),
          missingEnv: communications.channels?.sms?.missingEnv || []
        },
        whatsapp: {
          configured: Boolean(communications.channels?.whatsapp?.configured),
          missingEnv: communications.channels?.whatsapp?.missingEnv || []
        }
      },
      telehealth: {
        selectedProvider: telehealth.selectedProvider,
        configured: Boolean(telehealth.configured),
        dailyConfigured: dailyMissing.length === 0,
        missingEnv: telehealth.missingEnv || [],
        dailyMissingEnv: dailyMissing
      },
      pharmacy: {
        configured: Boolean(pharmacy.configured),
        missingEnv: pharmacy.missingEnv || []
      },
      mobileClinic: {
        configured: Boolean(mobileClinic.configured),
        missingEnv: mobileClinic.missingEnv || []
      }
    },
    providerRecipientEmails: nexusProductionConfiguredEnv(env, NEXUS_PRODUCTION_PROVIDER_EMAIL_ENVS),
    providerDestinations: nexusProductionConfiguredEnv(env, NEXUS_PRODUCTION_PROVIDER_DESTINATION_ENVS),
    missingEnv,
    noSecretValuesReturned: true,
    noAuthHeadersReturned: true,
    smokeSendFlagEnabled: String(env.NEXUS_ENABLE_PRODUCTION_PROVIDER_SMOKE_SENDS || "false").toLowerCase() === "true"
  };
}

function nexusKnowledgeCategoryForQuestion(question = "") {
  const lower = String(question || "").toLowerCase();
  if (/\b(telehealth|virtual visit|video visit|doctor visit|provider visit|intake)\b/.test(lower)) return "telehealth";
  if (/\b(pharmacy|medicine|medication|drug|prescription|refill|insulin storage|safe storage practices for insulin)\b/.test(lower)) return "pharmacy";
  if (/\b(mobile clinic|community health|outreach clinic|clinic schedule|clinic van)\b/.test(lower)) return "mobileClinic";
  if (/\b(blood pressure|bp|hypertension|diabetes|glucose|obesity|weight|chronic|rpm|rtm)\b/.test(lower)) return "chronicCare";
  if (/\b(blood pressure|hypertension|diabetes|obesity|chronic|health|symptom|doctor|clinic|medical|patient)\b/.test(lower)) return "health";
  if (/\b(price|market|buyer|seller|sell|agritrade|commodity|current market price)\b/.test(lower)) return "marketplace";
  if (/\b(crop|maize|tomato|tomatoes|cassava|soil|pest|farm|farmer|agriculture|irrigation|fertilizer|yellow leaves)\b/.test(lower)) return "agriculture";
  if (/\b(job|jobs|workforce|career|training|solar installation|skills|employment)\b/.test(lower)) return "jobs";
  if (/\b(lesson|learning|literacy|course|study|school|training)\b/.test(lower)) return "learning";
  if (/\b(route|map|field visit|distance|travel|directions)\b/.test(lower)) return "maps";
  if (/\b(music|media|song|playlist|r&b|rnb|afrobeats|african music|amapiano|gospel|spotify|youtube|apple music)\b/.test(lower)) return "music_media";
  if (/\b(reminder|reminders|remind me|follow up|follow-up)\b/.test(lower)) return "reminders";
  if (/\b(offline|low bandwidth|low-bandwidth|queue for later|save for later)\b/.test(lower)) return "offline";
  if (/\b(provider|admin|administrator|review queue|operations|partner account)\b/.test(lower)) return "providerAdmin";
  return "general";
}

function nexusKnowledgeNeedsRetrieval(question = "") {
  const lower = String(question || "").toLowerCase();
  return /\b(current|latest|today|now|recent|source|sources|cite|citation|price|market|available|growing|what causes|what should|safe storage|advice|guidance|training|jobs|weather)\b/.test(lower);
}

function nexusKnowledgeClassifier(question = "", context = {}) {
  const category = NEXUS_KNOWLEDGE_TRUSTED_SOURCES[context.category] ? context.category : nexusKnowledgeCategoryForQuestion(question);
  const retrievalNeeded = nexusKnowledgeNeedsRetrieval(question);
  const source = NEXUS_KNOWLEDGE_TRUSTED_SOURCES[category] || NEXUS_KNOWLEDGE_TRUSTED_SOURCES.general;
  const missingInformation = [];
  const lower = String(question || "").toLowerCase();
  if (category === "agriculture" && !/\b(maize|corn|tomato|tomatoes|cassava|rice|beans|crop|soil|field|region|kenya|ghana|nigeria|stockton|california)\b/.test(lower)) {
    missingInformation.push("crop and region");
  }
  if ((category === "maps" || category === "mobileClinic") && !/\b(city|village|region|near|from|to|clinic|county|state)\b/.test(lower)) {
    missingInformation.push("typed location or nearest landmark");
  }
  return {
    ok: true,
    question: sanitizePilotText(question, 500),
    category,
    categoryLabel: source.label,
    retrievalNeeded,
    trustedSourceCategory: {
      id: category,
      label: source.label,
      preferredSources: source.preferredSources,
      safetyNote: source.safetyNote
    },
    missingInformation,
    safetyFlags: nexusKnowledgeSafetyFlags(category, question)
  };
}

function nexusKnowledgeSafetyFlags(category = "general", question = "") {
  const lower = String(question || "").toLowerCase();
  return {
    noDiagnosis: ["health", "chronicCare", "telehealth", "pharmacy", "mobileClinic"].includes(category),
    noPrescribing: ["health", "chronicCare", "telehealth", "pharmacy"].includes(category),
    noDoseChanges: ["health", "chronicCare", "pharmacy"].includes(category),
    noEmergencyServiceClaim: true,
    noProviderContact: true,
    noPayment: true,
    noLiveJobClaimUnlessRetrieved: category === "jobs",
    noCurrentPriceClaimUnlessRetrieved: category === "marketplace",
    urgentLanguageDetected: /\b(chest pain|cannot breathe|not breathing|stroke|severe|bleeding|emergency)\b/.test(lower),
    noFakeCitations: true
  };
}

function nexusProviderPathwayTypeForCategory(category = "general") {
  if (["health", "chronicCare", "telehealth"].includes(category)) return "telehealth";
  if (category === "pharmacy") return "pharmacy";
  if (category === "mobileClinic") return "mobile_clinic";
  if (category === "agriculture") return "agriculture_advisor";
  if (category === "jobs") return "workforce_partner";
  if (category === "learning") return "learning_partner";
  if (category === "marketplace") return "marketplace_partner";
  if (category === "maps") return "logistics_partner";
  return "community_support";
}

function nexusProviderPathwayLabel(providerType = "community_support") {
  return ({
    telehealth: "Health / Telehealth Provider",
    pharmacy: "Pharmacy Review",
    mobile_clinic: "Mobile Clinic / Community Health",
    agriculture_advisor: "Agriculture Advisor / Agronomist",
    agronomist: "Agriculture Advisor / Agronomist",
    workforce_partner: "Workforce / Learning Partner",
    learning_partner: "Workforce / Learning Partner",
    marketplace_partner: "Marketplace / Logistics Partner",
    logistics_partner: "Marketplace / Logistics Partner",
    community_support: "Community Support"
  })[providerType] || "Provider/Partner Support";
}

function nexusProviderPathwayOffer(db, category = "general", question = "") {
  ensureNexusProductionRailsState(db);
  const providerType = nexusProviderPathwayTypeForCategory(category);
  const matchingProviders = db.nexusProviderOrganizations.filter(org => {
    if (![providerType, "admin_internal"].includes(org.organizationType)) return false;
    return org.status === "active";
  });
  const configured = matchingProviders.length > 0;
  const label = nexusProviderPathwayLabel(providerType);
  return {
    ok: true,
    providerTypeRequested: providerType,
    label,
    configured,
    configuredProviderCount: matchingProviders.length,
    status: configured ? "provider_pathway_available" : "provider_pathway_not_configured",
    headline: "Need provider support?",
    copy: "Nexus can prepare this for provider/advisor review. If a live provider is configured, it can be routed after your consent. If not, it will be saved locally for review.",
    availableActions: [
      "save_to_workflow",
      "prepare_provider_summary",
      "request_provider_advisor_review",
      ...(providerType === "telehealth" ? ["start_telehealth_intake"] : []),
      ...(providerType === "pharmacy" ? ["prepare_pharmacy_note"] : []),
      ...(providerType === "agriculture_advisor" ? ["request_agriculture_advisor_support", "prepare_field_visit_note"] : []),
      ...(providerType === "mobile_clinic" ? ["request_mobile_clinic_community_support"] : [])
    ],
    configuredCopy: configured ? "Provider pathway available after consent and final review." : "Provider pathway not configured yet; Nexus can save this locally.",
    noSentClaim: true,
    noLiveProviderClaimUnlessConfigured: true,
    question: sanitizePilotText(question, 400)
  };
}

function normalizeNexusKnowledgeCitations(results = []) {
  const retrievedAt = new Date().toISOString();
  return (Array.isArray(results) ? results : [])
    .filter(item => item && item.url)
    .slice(0, 5)
    .map((item, index) => {
      let domain = "";
      try { domain = new URL(item.url).hostname.replace(/^www\./, ""); } catch {}
      return {
      id: `source-${index + 1}`,
      title: sanitizePilotText(item.title || item.url || "Source", 180),
      url: sanitizePilotText(item.url || "", 500),
      domain: sanitizePilotText(domain || item.source || "", 160),
      publisher: sanitizePilotText(item.publisher || item.source || domain || "", 160),
      source: sanitizePilotText(item.source || item.title || item.url || "Source", 180),
      snippet: sanitizePilotText(item.snippet || "", 280),
      sourceSummary: sanitizePilotText(item.snippet || "", 280),
      retrievedAt,
      category: sanitizePilotText(item.category || "", 80),
      sourceTrustLabel: "retrieved_source",
      sourceType: "web"
      };
    });
}

function nexusKnowledgeSafetyCopy(category = "general") {
  const source = NEXUS_KNOWLEDGE_TRUSTED_SOURCES[category] || NEXUS_KNOWLEDGE_TRUSTED_SOURCES.general;
  if (category === "health" || category === "chronicCare" || category === "telehealth" || category === "pharmacy" || category === "mobileClinic") {
    return `${source.safetyNote} If symptoms may be urgent, contact local emergency services or a qualified clinician immediately.`;
  }
  return source.safetyNote;
}

function nexusKnowledgeBuiltInGuidance(question = "", category = "general") {
  const source = NEXUS_KNOWLEDGE_TRUSTED_SOURCES[category] || NEXUS_KNOWLEDGE_TRUSTED_SOURCES.general;
  const lower = String(question || "").toLowerCase();
  if (category === "chronicCare" || category === "health") {
    if (/\b(145\/92|blood pressure|bp|hypertension)\b/.test(lower)) {
      return "That blood pressure reading can be organized for review. Nexus can help you record the number, note symptoms, list medications, and prepare questions for a clinician. Do not change medication based on this app alone.";
    }
    return "Nexus can provide education and help organize symptoms, readings, questions, and care-team summaries. It does not diagnose, prescribe, or replace a clinician.";
  }
  if (category === "telehealth") return "Nexus can help prepare a telehealth intake: symptoms, timing, medications, questions, and documents to review before a visit. It does not book or connect a clinician unless a verified provider integration is configured.";
  if (category === "pharmacy") return "Nexus can help prepare medication questions and organize pharmacy notes for review. It does not refill prescriptions, prescribe, change doses, or contact a pharmacy.";
  if (category === "agriculture") return "Nexus can help organize crop, region, weather, soil, watering, pest signs, photos, and field notes so an agriculture expert or extension source can review the issue.";
  if (category === "jobs") return "Nexus can help build a workforce plan, list target skills, prepare training questions, and save next steps. Live openings require a configured current source.";
  if (category === "learning") return "Nexus can help build a learning plan, choose topics, organize literacy support, and prepare training questions.";
  if (category === "marketplace") return "Nexus can help prepare a marketplace draft with item, quantity, location, quality, pricing questions, and logistics notes. It does not claim current prices or complete transactions without configured sources and approvals.";
  if (category === "maps") return "Nexus can prepare a field visit note using typed locations. It does not request browser location or claim live routing unless a route provider is configured.";
  if (category === "mobileClinic") return "Nexus can prepare community health access notes and questions. It does not dispatch a mobile clinic.";
  if (category === "music_media") return "Nexus can prepare safe provider search options for music and media. It does not host, download, rip, cache, redistribute, or claim live playback.";
  if (category === "reminders") return "Nexus can turn follow-up ideas into local reminder suggestions. It does not send SMS, push, calendar, or provider notifications unless a configured provider and approval path are active.";
  if (category === "offline") return "Nexus can save this question or summary locally for later review. It does not claim background sync, provider routing, or external delivery unless configured.";
  return `Nexus can organize this as ${source.label.toLowerCase()} guidance, ask for missing details, and save it for review.`;
}

function nexusKnowledgeKeyPoints(answer = "", category = "general", mode = "disabled") {
  if (mode === "retrieved") {
    return [
      "Nexus found citable source material through a configured retrieval provider.",
      "Review the citations and the date retrieved before acting.",
      "Use the follow-up actions to save, attach, or prepare a review summary."
    ];
  }
  if (mode === "built_in") {
    return [
      "This is built-in Nexus guidance, not a live internet result.",
      "Nexus can organize your details and prepare a local record.",
      "Live current claims require a configured retrieval provider."
    ];
  }
  return [
    "Live internet retrieval is not configured in this runtime.",
    "Nexus did not create fake citations or source links.",
    "You can save this question or prepare it for review."
  ];
}

